W('/init.lua', [[
-- OCOS /init.lua
-- Loaded by the EEPROM BIOS. Reads /sys/boot.lua via raw component calls
-- (the filesystem library is not loaded yet) and yields control to it.

local boot_addr = computer.getBootAddress()
local invoke = component.invoke

local function read_all(path)
  local handle, err = invoke(boot_addr, "open", path)
  if not handle then error("init: cannot open " .. path .. ": " .. tostring(err), 0) end
  local parts, chunk = {}, nil
  repeat
    chunk = invoke(boot_addr, "read", handle, math.maxinteger or math.huge)
    if chunk then parts[#parts + 1] = chunk end
  until not chunk
  invoke(boot_addr, "close", handle)
  return table.concat(parts)
end

local boot_src = read_all("/sys/boot.lua")
local boot_fn, load_err = load(boot_src, "=/sys/boot.lua", "t", _G)
if not boot_fn then error("init: cannot load /sys/boot.lua: " .. tostring(load_err), 0) end
return boot_fn(boot_addr, read_all)
]])
W('/sys/boot.lua', [[
-- /sys/boot.lua — bootstrap layer.
--
-- /init.lua hands us the boot filesystem address and a raw read_all helper
-- (the VFS isn't loaded yet). We build a minimal `require` rooted at /sys/,
-- bring up the kernel modules in dependency order, fire each driver's
-- registration logic, replay component_added so they discover existing
-- hardware, spawn the init service, and hand control to the scheduler,
-- which never returns.

local boot_addr, read_all = ...

_G._OSVERSION = "OCOS 0.1.0"
_G._OCOS = { boot_addr = boot_addr, started_at = computer.uptime() }

-- ---- Minimal require rooted at /sys/ ------------------------------------

local loaded = {}
local function _require(name)
  if loaded[name] then return loaded[name] end
  local rel = name:gsub("%.", "/")
  local candidates = { "/sys/" .. rel .. ".lua", "/sys/" .. rel .. "/init.lua" }
  local src, src_path
  for _, p in ipairs(candidates) do
    local ok, data = pcall(read_all, p)
    if ok then src, src_path = data, p; break end
  end
  if not src then error("require: module not found: " .. name, 2) end
  local chunk, err = load(src, "=" .. src_path, "t", _G)
  if not chunk then error("require: cannot load " .. name .. ": " .. tostring(err), 0) end
  loaded[name] = true
  local result = chunk()
  loaded[name] = result == nil and true or result
  return loaded[name]
end
_G.require = _require

-- ---- Kernel boot order --------------------------------------------------

local log    = _require("k.log");    log.init({ ring_size = 256 })
local panic  = _require("k.panic");  panic.init()
local signal = _require("k.signal"); signal.init()
local ipc    = _require("k.ipc");    ipc.init()
local cap    = _require("k.cap");    cap.init({ enforce = false })
-- /etc/security.cfg may flip enforcement on after the kernel and VFS are
-- up. We read it here, after vfs.init, but the file lives on the boot fs
-- so we have to defer this read to the post-vfs section below.
local vfs    = _require("k.vfs");    vfs.init({ boot_addr = boot_addr })
local proc   = _require("k.proc");   proc.init()
local sched  = _require("k.sched");  sched.init()

log.info("boot", _OSVERSION .. " booting on " .. boot_addr:sub(1, 8))

-- Apply security policy now that the VFS is mounted.
do
  local sec_path = "/etc/security.cfg"
  if vfs.exists(sec_path) then
    local src = vfs.read_all(sec_path)
    local fn, err = load(src or "", "=" .. sec_path, "t", {})
    if fn then
      local ok, t = pcall(fn)
      if ok and type(t) == "table" then
        cap.set_enforce(t.enforce == true)
        log.info("boot", "security: enforce=" .. tostring(t.enforce == true))
      else
        log.warn("boot", "security.cfg eval: " .. tostring(t))
      end
    else
      log.warn("boot", "security.cfg syntax: " .. tostring(err))
    end
  end
end

-- ---- Drivers ------------------------------------------------------------

_require("drv.gpu").init()
_require("drv.screen").init()
_require("drv.kbd").init()
_require("drv.fs").init()

-- ---- Replay component_added so drivers discover already-attached hw -----

for addr, ctype in component.list() do
  ipc.publish("oc.signal.component_added", table.pack(addr, ctype))
end

-- ---- First user process -------------------------------------------------

local init_svc = _require("svc.init")
sched.spawn(init_svc.main, { name = "init", caps = { "*" } })

-- ---- Hand control to the scheduler --------------------------------------

log.info("boot", "kernel initialised, entering scheduler")
sched.run()                                      -- does not return
]])
W('/sys/drv/fs.lua', [[
-- /sys/drv/fs.lua — auto-mount external filesystems at /mnt/<addr-prefix>/.
-- The boot filesystem is already mounted at "/" by k.vfs; this driver only
-- handles non-boot filesystems and hot-plug.

local M = {}

local ipc = require("k.ipc")
local vfs = require("k.vfs")
local log = require("k.log")

local mounted                                    -- {addr -> mountpoint}

local function mount_fs(addr)
  if mounted[addr] then return end
  if addr == _OCOS.boot_addr then return end     -- already at "/"
  local mp = "/mnt/" .. addr:sub(1, 8)
  -- /mnt may not exist on boot fs — that's fine, mount table is purely virtual
  local ok, err = vfs.mount(component.proxy(addr), mp)
  if ok then
    mounted[addr] = mp
    log.info("fs", "mounted " .. addr:sub(1, 8) .. " at " .. mp)
  else
    log.warn("fs", "mount " .. addr:sub(1, 8) .. " failed: " .. tostring(err))
  end
end

local function umount_fs(addr)
  local mp = mounted[addr]
  if not mp then return end
  vfs.umount(mp)
  mounted[addr] = nil
  log.info("fs", "umounted " .. addr:sub(1, 8))
end

function M.init()
  mounted = {}
  ipc.subscribe("oc.signal.component_added", function(p)
    local addr, ctype = p[1], p[2]
    if ctype == "filesystem" then mount_fs(addr) end
  end)
  ipc.subscribe("oc.signal.component_removed", function(p)
    local addr, ctype = p[1], p[2]
    if ctype == "filesystem" then umount_fs(addr) end
  end)
  for addr in component.list("filesystem") do mount_fs(addr) end
end

return M
]])
W('/sys/drv/gpu.lua', [[
-- /sys/drv/gpu.lua — GPU driver.
-- Owns one (gpu, screen) pair and exposes text-cell primitives. The compositor
-- in lib/ui sits on top of these and adds off-screen buffer allocation +
-- dirty-rect tracking; the driver itself stays a thin OC-API wrapper.

local M = {}

local ipc = require("k.ipc")
local log = require("k.log")

local active                                     -- {addr, proxy, screen_addr, w, h, depth}

local function bind_pair(gpu_addr, screen_addr)
  local proxy = component.proxy(gpu_addr)
  -- The EEPROM bios already calls gpu.bind(screen) before /init.lua runs, so
  -- we only re-bind if the active screen has changed (e.g. on hot-plug).
  local current = proxy.getScreen and proxy.getScreen() or screen_addr
  if current ~= screen_addr then
    local ok, err = proxy.bind(screen_addr)
    if not ok then
      log.warn("gpu", "bind failed " .. gpu_addr:sub(1, 8) .. " -> " .. screen_addr:sub(1, 8) .. ": " .. tostring(err))
      return nil
    end
  end
  -- Use whatever resolution the BIOS left active. Bumping to maxResolution
  -- on tier-1 GPUs in some emulators triggers "unsupported resolution".
  local w, h = proxy.getResolution()
  proxy.setBackground(0x000000)
  proxy.setForeground(0xCCCCCC)
  proxy.fill(1, 1, w, h, " ")
  log.info("gpu", "active " .. gpu_addr:sub(1, 8) .. " -> " .. screen_addr:sub(1, 8) .. " (" .. w .. "x" .. h .. ")")
  return { addr = gpu_addr, proxy = proxy, screen_addr = screen_addr, w = w, h = h }
end

local function try_bind()
  if active then return end
  local gpu_addr = component.list("gpu")()
  local screen_addr = component.list("screen")()
  if gpu_addr and screen_addr then
    active = bind_pair(gpu_addr, screen_addr)
    if active then ipc.publish("ui.gpu.bound", { gpu = gpu_addr, screen = screen_addr, w = active.w, h = active.h }) end
  end
end

function M.init()
  ipc.subscribe("oc.signal.component_added", function(p)
    local _, ctype = p[1], p[2]
    if ctype == "gpu" or ctype == "screen" then try_bind() end
  end)
  ipc.subscribe("oc.signal.component_removed", function(p)
    local addr = p[1]
    if active and (addr == active.addr or addr == active.screen_addr) then
      log.warn("gpu", "active component lost; rebinding")
      active = nil
      try_bind()
    end
  end)
  try_bind()
end

function M.active() return active end

function M.set(x, y, s)            return active and active.proxy.set(x, y, s) end
function M.fill(x, y, w, h, ch)    return active and active.proxy.fill(x, y, w, h, ch or " ") end
function M.copy(x, y, w, h, dx, dy) return active and active.proxy.copy(x, y, w, h, dx, dy) end
function M.size()                  return active and active.w, active and active.h end
function M.set_fg(c)               return active and active.proxy.setForeground(c) end
function M.set_bg(c)               return active and active.proxy.setBackground(c) end
function M.get_fg()                return active and active.proxy.getForeground() end
function M.get_bg()                return active and active.proxy.getBackground() end
function M.clear()
  if not active then return end
  active.proxy.fill(1, 1, active.w, active.h, " ")
end

return M
]])
W('/sys/drv/internet.lua', [[
-- /sys/drv/internet.lua — wraps the OC internet card.
--
-- Provides:
--   net.has_internet()           true if a card is attached and HTTP enabled
--   net.http_request(url, opts)  blocks until the response is received,
--                                returns body, status, headers (or nil, err)
--   net.tcp_connect(host, port)  returns a Stream-shaped object, or nil, err
--
-- The HTTP path uses the card's request handle: we poll read() until the
-- card returns nil (EOF). For correctness under the 5-s watchdog we yield
-- between reads and bound the total wait via opts.timeout (default 30s).

local M = {}

local sched   = require("k.sched")
local stream  = require("std.stream")
local log     = require("k.log")

local function pick_card()
  local addr = component.list("internet")()
  if not addr then return nil end
  return component.proxy(addr), addr
end

function M.init()
  local card, addr = pick_card()
  if card then log.info("internet", "card available: " .. addr:sub(1, 8)) end
end

function M.has_internet()
  local card = pick_card()
  return card and card.isHttpEnabled and card.isHttpEnabled() == true
end

local function read_handle_to_string(handle, timeout)
  local deadline = computer.uptime() + (timeout or 30)
  local parts = {}
  while computer.uptime() < deadline do
    local chunk, err = handle.read(8192)
    if chunk == nil then
      if err then return nil, tostring(err) end
      break
    end
    if chunk == "" then sched.sleep(0.05) else parts[#parts + 1] = chunk end
  end
  if computer.uptime() >= deadline then return nil, "timeout" end
  return table.concat(parts)
end

function M.http_request(url, opts)
  opts = opts or {}
  local card, addr = pick_card()
  if not card then return nil, "no internet card" end
  if card.isHttpEnabled and not card.isHttpEnabled() then
    return nil, "http disabled by host"
  end
  local handle, err = card.request(url, opts.body, opts.headers)
  if not handle then return nil, "request: " .. tostring(err) end
  -- The card's handle exposes finishConnect()/response()/read()/close().
  local started = computer.uptime()
  local timeout = opts.timeout or 30
  while not handle.finishConnect() do
    if computer.uptime() - started > timeout then
      handle.close(); return nil, "connect timeout"
    end
    sched.sleep(0.1)
  end
  local status, msg, headers = handle.response()
  local body, berr = read_handle_to_string(handle, timeout)
  handle.close()
  if not body then return nil, berr end
  return body, status, headers
end

local function wrap_tcp_handle(handle)
  local closed = false
  local read_buffer = ""
  return stream.new {
    _read = function(self, n)
      if closed and read_buffer == "" then return nil end
      while not closed and #read_buffer < (n or 1) do
        local chunk = handle.read(n or 4096)
        if chunk == nil then closed = true; break end
        if chunk == "" then sched.sleep(0.05) else read_buffer = read_buffer .. chunk end
      end
      local out = read_buffer:sub(1, n or #read_buffer)
      read_buffer = read_buffer:sub((n or #read_buffer) + 1)
      if out == "" and closed then return nil end
      return out
    end,
    _write = function(s, data)
      if closed then return nil, "closed" end
      handle.write(data)
      return s
    end,
    _close = function()
      if not closed then handle.close(); closed = true end
      return true
    end,
  }
end

function M.tcp_connect(host, port, timeout)
  local card = pick_card()
  if not card or not card.connect then return nil, "no tcp-capable card" end
  if card.isTcpEnabled and not card.isTcpEnabled() then return nil, "tcp disabled" end
  local handle, err = card.connect(host, port)
  if not handle then return nil, "connect: " .. tostring(err) end
  local started = computer.uptime()
  while not handle.finishConnect() do
    if computer.uptime() - started > (timeout or 30) then
      handle.close(); return nil, "connect timeout"
    end
    sched.sleep(0.05)
  end
  return wrap_tcp_handle(handle)
end

return M
