-- /sys/lib/codec/hmac.lua — HMAC-SHA256 over the codec/sha256 primitive.

local M = {}

local sha = require("lib.codec.sha256")

local BLOCK = 64

local function xor_pad(key, b)
  -- Lua 5.3 has bitwise ops on integers; bytewise XOR via string.byte.
  local out = {}
