end

local function decode_object(state)
  expect(state, "{")
  local obj = {}
  skip_ws(state)
  if state.src:sub(state.pos, state.pos) == "}" then state.pos = state.pos + 1; return obj end
  while true do
    skip_ws(state)
    if state.src:sub(state.pos, state.pos) ~= '"' then decode_error(state, "expected key string") end
