  for i = 1, 16 do
    local p = off + (i - 1) * 4
    W[i] =
      shl(msg:byte(p + 1), 24) +
      shl(msg:byte(p + 2), 16) +
      shl(msg:byte(p + 3),  8) +
          msg:byte(p + 4)
