  for i = 17, 64 do
    local s0 = bxor(bxor(rotr(W[i - 15], 7),  rotr(W[i - 15], 18)), shr(W[i - 15], 3))
    local s1 = bxor(bxor(rotr(W[i - 2],  17), rotr(W[i - 2],  19)), shr(W[i - 2],  10))
