-- /sys/lib/devtools/inspect.lua — pretty-printer for Lua values.
--
-- Cycle-safe: tables are tagged on first visit and printed as `<table:N>`
-- on revisit. Keys are sorted (numbers before strings, then lexicographic).
-- Strings longer than `max_string` are truncated with an ellipsis.

local M = {}

local function default_opts(o)
  o = o or {}
  o.max_depth  = o.max_depth  or 6
  o.max_string = o.max_string or 200
  o.max_keys   = o.max_keys   or 64
  return o
end

local function key_lt(a, b)
  local ta, tb = type(a), type(b)
  if ta == tb then
    if ta == "number" then return a < b end
    return tostring(a) < tostring(b)
  end
  return ta == "number"
end

local function fmt_string(s, opts)
  if #s > opts.max_string then s = s:sub(1, opts.max_string) .. "…" end
  return string.format("%q", s)
end

local function inspect_value(v, opts, depth, seen, out)
  local t = type(v)
  if t == "string" then out[#out + 1] = fmt_string(v, opts); return end
  if t == "number" or t == "boolean" or t == "nil" then out[#out + 1] = tostring(v); return end
  if t == "function" then out[#out + 1] = "<function>"; return end
  if t == "userdata" then out[#out + 1] = "<userdata>"; return end
  if t == "thread" then out[#out + 1] = "<thread>"; return end
  if t ~= "table" then out[#out + 1] = "<" .. t .. ">"; return end

  if seen[v] then out[#out + 1] = "<table:" .. seen[v] .. ">"; return end
  seen.count = (seen.count or 0) + 1
  seen[v] = seen.count
  if depth >= opts.max_depth then out[#out + 1] = "<table:" .. seen[v] .. " ...>"; return end

  local keys = {}
  for k in pairs(v) do keys[#keys + 1] = k end
  table.sort(keys, key_lt)
  if #keys == 0 then out[#out + 1] = "{}"; return end

  out[#out + 1] = "{\n"
  local indent = string.rep("  ", depth + 1)
  local close = string.rep("  ", depth)
  for i, k in ipairs(keys) do
    if i > opts.max_keys then
      out[#out + 1] = indent .. "... (" .. (#keys - opts.max_keys) .. " more)\n"
      break
    end
    out[#out + 1] = indent
    if type(k) == "string" and k:match("^[%a_][%w_]*$") then
      out[#out + 1] = k
    else
      out[#out + 1] = "[" .. (type(k) == "string" and fmt_string(k, opts) or tostring(k)) .. "]"
    end
    out[#out + 1] = " = "
    inspect_value(v[k], opts, depth + 1, seen, out)
    out[#out + 1] = ",\n"
  end
  out[#out + 1] = close .. "}"
end

function M.inspect(value, opts)
  local out = {}
  inspect_value(value, default_opts(opts), 0, {}, out)
  return table.concat(out)
end

function M.print(value, opts)
  io.write(M.inspect(value, opts), "\n")
end

return M
]])
W('/sys/lib/devtools/profile.lua', [[
-- /sys/lib/devtools/profile.lua — wall-time micro-benchmarks.
--
-- The OpenComputers sandbox does not expose debug.sethook to user code
-- (it is reserved for the watchdog), so a sampling profiler is not
-- possible. We provide an explicit time-it API instead, sufficient for
-- comparing implementations and tracking per-iteration cost.
--
-- Usage:
--   local prof = require("lib.devtools.profile")
--   local report = prof.bench("sha256(1KB)", 100, function()
--     sha.hex(string.rep("x", 1024))
--   end)
--   print(prof.format({report}))

local M = {}

local function now() return computer.uptime() end

function M.time(fn, ...)
  local args = table.pack(...)
  local start = now()
  fn(table.unpack(args, 1, args.n))
  return now() - start
end

function M.bench(name, iterations, fn)
  local before = now()
  for _ = 1, iterations do fn() end
  local elapsed = now() - before
  return {
    name        = name,
    iterations  = iterations,
    elapsed_s   = elapsed,
    per_iter_ms = elapsed * 1000 / iterations,
  }
end

function M.format(rows)
  local lines = { string.format("%-32s  %8s  %14s  %14s",
    "BENCH", "ITERS", "TOTAL (ms)", "PER ITER (ms)") }
  for _, r in ipairs(rows) do
    lines[#lines + 1] = string.format("%-32s  %8d  %14.2f  %14.4f",
      r.name, r.iterations, r.elapsed_s * 1000, r.per_iter_ms)
  end
  return table.concat(lines, "\n")
end

return M
]])
W('/sys/lib/lang.lua', [[
-- /sys/lib/lang.lua — translation dictionary loader.
--
-- Locales live at /etc/locale/<code>.lua and return a flat table from
-- string keys to translated strings. Lookup falls back to English when a
-- key is missing, then to the key itself wrapped in `<...>` so missing
-- translations are visually obvious.
--
-- Apps and the OS reach strings via `lang.t("dock.terminal")` etc.;
-- changing the active locale is one call (`lang.set("uk")`) plus an IPC
-- broadcast on `lang.changed` for live UI updates.

local M = {}

local vfs = require("k.vfs")
local ipc = require("k.ipc")

local current_code     -- string locale code
local current_table    -- {key -> translated}
local fallback_table   -- english, always loaded

local function load_locale(code)
  local path = "/etc/locale/" .. code .. ".lua"
  if not vfs.exists(path) then return nil, "locale not found: " .. code end
  local src = vfs.read_all(path)
  local fn, err = load(src or "", "=" .. path, "t", {})
  if not fn then return nil, "locale syntax: " .. tostring(err) end
  local ok, t = pcall(fn)
  if not ok or type(t) ~= "table" then return nil, "locale eval: " .. tostring(t) end
  return t
end

function M.set(code)
  local t, err = load_locale(code)
  if not t then return nil, err end
  current_code, current_table = code, t
  ipc.publish("lang.changed", { code = code })
  return true
end

function M.code() return current_code or "en" end

function M.t(key, ...)
  local v = current_table and current_table[key]
  if v == nil and fallback_table then v = fallback_table[key] end
  if v == nil then return "<" .. key .. ">" end
  if select("#", ...) > 0 then return string.format(v, ...) end
  return v
end

function M.list_available()
  local result = {}
  if vfs.isdir("/etc/locale") then
    for _, name in ipairs(vfs.list("/etc/locale") or {}) do
      if name:sub(-4) == ".lua" then result[#result + 1] = name:sub(1, -5) end
    end
    table.sort(result)
  end
  return result
end

-- Default activation: English fallback always loaded; runtime locale comes
-- from /etc/locale.cfg's `default` entry, which can be overridden by the
-- session environment.
do
  fallback_table = load_locale("en") or {}
  local cfg_path = "/etc/locale.cfg"
  if vfs.exists(cfg_path) then
    local src = vfs.read_all(cfg_path)
    local fn = load(src or "", "=" .. cfg_path, "t", {})
    if fn then
      local ok, cfg = pcall(fn)
      if ok and type(cfg) == "table" and cfg.default then
        local ok2 = M.set(cfg.default)
        if not ok2 then current_code, current_table = "en", fallback_table end
      end
    end
  end
  if not current_code then current_code, current_table = "en", fallback_table end
end

return M
]])
W('/sys/lib/net/rpc.lua', [[
-- /sys/lib/net/rpc.lua — JSON-RPC 2.0 over modem sockets.
--
-- Server side:
--   rpc.serve(port, methods)  blocks while serving registered handlers.
-- Client side:
--   rpc.call(target_addr, port, method, params, timeout)
--
-- `methods` is { name = function(params, ctx) -> result | error("string") }.
-- Errors raised inside a handler become a JSON-RPC error response with
-- code -32000 and the error string as message.

local M = {}

local sock  = require("lib.net.sock")
local json  = require("lib.codec.json")
local sched = require("k.sched")

local function next_id(state)
  state.id = (state.id or 0) + 1
  return state.id
end

function M.call(target_addr, port, method, params, timeout)
  local state = M._client_state or { id = 0, sockets = {}, sock = nil }
  M._client_state = state
  if not state.sock then state.sock = sock.bind(port) end
  local id = next_id(state)
  local req = json.encode({ jsonrpc = "2.0", id = id, method = method, params = params or json.null })
  state.sock:send(target_addr, req)
  local deadline = computer.uptime() + (timeout or 5)
  while computer.uptime() < deadline do
    local msg = state.sock:recv(deadline - computer.uptime())
    if msg then
      local body = msg.payload[1]
      local parsed, perr = json.decode(body or "")
      if parsed and parsed.id == id then
        if parsed.error then return nil, parsed.error.message or "rpc error" end
        return parsed.result
      end
    end
  end
  return nil, "rpc timeout"
end

function M.serve(port, methods)
  local s = sock.bind(port)
  while true do
    local msg = s:recv()
    if msg then
      local body = msg.payload[1]
      local parsed, perr = json.decode(body or "")
      if parsed then
        local handler = methods[parsed.method]
        local response
        if not handler then
          response = { jsonrpc = "2.0", id = parsed.id,
                       error = { code = -32601, message = "method not found" } }
        else
          local ok, ret = pcall(handler, parsed.params, { sender = msg.sender })
          if ok then response = { jsonrpc = "2.0", id = parsed.id, result = ret }
          else response = { jsonrpc = "2.0", id = parsed.id,
                            error = { code = -32000, message = tostring(ret) } } end
        end
        s:send(msg.sender, json.encode(response))
      end
    end
  end
end

return M
]])
W('/sys/lib/net/sock.lua', [[
-- /sys/lib/net/sock.lua — datagram sockets over modem/tunnel.
--
-- Each socket binds a port (or, on a tunnel, accepts the implicit channel)
-- and exposes:
--   :send(addr, ...)
--   :broadcast(...)
--   :recv(timeout)  -> {sender, port, distance, payload[]}, or nil on timeout
--   :close()
--
-- recv yields cooperatively via sched.wait so multiple processes can share
-- the modem peacefully.

local M = {}

local sched = require("k.sched")
local ipc   = require("k.ipc")
local modem = require("drv.modem")

local Socket = {}
Socket.__index = Socket

function Socket:send(addr, ...) return modem.send(addr, self.port, ...) end
function Socket:broadcast(...)  return modem.broadcast(self.port, ...) end
function Socket:close()
  if self.handle then ipc.unsubscribe(self.handle); self.handle = nil end
  if self.port and self._opened then modem.close(self.port) end
end

function Socket:recv(timeout)
  -- The sub-callback enqueues messages; recv yields until queue non-empty.
  local SIGNAL = "__sock_" .. self.port
  local q = self.queue
  local deadline = timeout and (computer.uptime() + timeout) or nil
  while #q == 0 do
    if deadline and computer.uptime() >= deadline then return nil end
    local remaining = deadline and (deadline - computer.uptime()) or math.huge
    sched.wait(function(name) return name == SIGNAL end, remaining)
  end
  return table.remove(q, 1)
end

function M.bind(port)
  local self = setmetatable({ port = port, queue = {}, _opened = false }, Socket)
  local SIGNAL = "__sock_" .. port
  local opened = modem.open(port)
  if opened ~= nil then self._opened = (opened == true) end
  self.handle = ipc.subscribe("net.message", function(msg)
    if msg.port == port or modem.address and select(2, modem.address()) == "tunnel" then
      self.queue[#self.queue + 1] = msg
      computer.pushSignal(SIGNAL)
    end
  end)
  return self
end

return M
]])
W('/sys/lib/pkg/db.lua', [[
-- /sys/lib/pkg/db.lua — installed-package registry persisted under
-- /var/db/pkg/<id>/manifest.cfg + installed.cfg.

local M = {}

local vfs = require("k.vfs")

local function pick_root()
  -- Prefer /var/db/pkg on the boot fs only if it's writable; otherwise look
  -- on the first writable mount and create the path there.
  if vfs.exists("/var/db/pkg") and vfs.exists("/var/db") then
    return "/var/db/pkg"
  end
  for _, m in ipairs(vfs.mounts()) do
    if m.prefix:sub(1, 5) == "/mnt/" then
      pcall(vfs.mkdir, m.prefix .. "/var")
      pcall(vfs.mkdir, m.prefix .. "/var/db")
      pcall(vfs.mkdir, m.prefix .. "/var/db/pkg")
      return m.prefix .. "/var/db/pkg"
    end
  end
end

function M.root() return pick_root() end

function M.list()
  local root = pick_root(); if not root then return {} end
  local entries = vfs.list(root) or {}
  local ids = {}
  for _, e in ipairs(entries) do
    if vfs.isdir(root .. "/" .. e) then ids[#ids + 1] = e end
  end
  table.sort(ids)
  return ids
end

function M.get(id)
  local root = pick_root(); if not root then return nil, "no db root" end
  local path = root .. "/" .. id .. "/manifest.cfg"
  if not vfs.exists(path) then return nil, "not installed" end
  return require("lib.pkg.manifest").load_file(path)
end

function M.put(manifest)
  local root = pick_root(); if not root then return nil, "no writable db root" end
  local dir = root .. "/" .. manifest.id
  pcall(vfs.mkdir, dir)
  local mfst = require("lib.pkg.manifest")
  local body = mfst.canonicalise(manifest)
  local ok, err = vfs.write_all(dir .. "/manifest.cfg", "return " .. body .. "\n")
  if not ok then return nil, err end
  return dir
end

function M.remove(id)
  local root = pick_root(); if not root then return nil, "no db root" end
  local dir = root .. "/" .. id
  if not vfs.exists(dir) then return nil, "not installed" end
  -- Recursive delete: enumerate then remove.
  local stack = { dir }
  local files, dirs = {}, {}
  while #stack > 0 do
    local d = table.remove(stack)
    dirs[#dirs + 1] = d
    for _, name in ipairs(vfs.list(d) or {}) do
      local sub = d .. "/" .. name
      if vfs.isdir(sub) then stack[#stack + 1] = sub
      else files[#files + 1] = sub end
    end
  end
  for _, f in ipairs(files) do pcall(vfs.remove, f) end
  for i = #dirs, 1, -1 do pcall(vfs.remove, dirs[i]) end
  return true
end

return M
]])
W('/sys/lib/pkg/install.lua', [[
-- /sys/lib/pkg/install.lua — install / uninstall a package from a local
-- directory. Files declared in the manifest are SHA-256-verified, then
-- copied into the OCOS filesystem at the path given by the manifest's
-- `prefix` field (default "/"). The destination paths are recorded in the
-- per-package row in /var/db/pkg/<id>/installed.cfg so uninstall can undo.

local M = {}

local vfs      = require("k.vfs")
local sha256   = require("lib.codec.sha256")
local manifest = require("lib.pkg.manifest")
local db       = require("lib.pkg.db")
local semver   = require("lib.codec.semver")

local function read_file(path)
  local s, err = vfs.read_all(path); if not s then return nil, err end
  return s
end

local function write_file(path, data)
  local h, err = vfs.open(path, "w"); if not h then return nil, err end
  local ok, werr = h:write(data)
  h:close()
  if not ok then return nil, werr end
  return true
end

local function ensure_dir(path)
  local parts = {}
  for p in path:gmatch("[^/]+") do parts[#parts + 1] = p end
  local cur = ""
  for i = 1, #parts - 1 do
    cur = cur .. "/" .. parts[i]
    if not vfs.exists(cur) then pcall(vfs.mkdir, cur)
    elseif not vfs.isdir(cur) then return nil, "not a directory: " .. cur end
  end
  return true
end

local function check_dependencies(manifest_t)
  local missing = {}
  for dep_id, constraint in pairs(manifest_t.depends) do
    local installed = db.get(dep_id)
    if not installed then
      missing[#missing + 1] = dep_id .. " (any)"
    else
      local ok = semver.satisfies(installed.version, constraint)
      if not ok then
        missing[#missing + 1] = dep_id .. " " .. constraint ..
          " (have " .. installed.version .. ")"
      end
    end
  end
  if #missing > 0 then
    return nil, "unsatisfied deps: " .. table.concat(missing, ", ")
  end
  return true
end

local function record_installed(manifest_t, written)
  -- Persist a small footprint table next to the manifest so uninstall can
  -- enumerate the destination paths without re-reading the source bundle.
  local lines = { "return {" }
  for _, p in ipairs(written) do
    lines[#lines + 1] = string.format("  %q,", p)
  end
  lines[#lines + 1] = "}\n"
  local root = db.root()
  return vfs.write_all(root .. "/" .. manifest_t.id .. "/installed.cfg",
                       table.concat(lines, "\n"))
end

function M.install_dir(source_dir, opts)
  opts = opts or {}
  local mfst, err = manifest.load_file(source_dir .. "/manifest.cfg")
  if not mfst then return nil, err end

  if not opts.force then
    local existing = db.get(mfst.id)
    if existing then
      return nil, "already installed (" .. existing.version ..
        "). Use `pkg install -f` to reinstall."
    end
  end

  local ok, derr = check_dependencies(mfst)
  if not ok then return nil, derr end

  -- Verify every declared file before touching the destination.
  for rel, meta in pairs(mfst.files) do
    local data, e = read_file(source_dir .. "/" .. rel)
    if not data then return nil, "missing file " .. rel .. ": " .. tostring(e) end
    local digest = sha256.hex(data)
    if digest ~= meta.sha256:lower() then
      return nil, "checksum mismatch on " .. rel ..
        " (expected " .. meta.sha256 .. ", got " .. digest .. ")"
    end
  end

  -- Copy.
  local prefix = mfst.prefix or "/"
  local written = {}
  for rel, _ in pairs(mfst.files) do
    local data = read_file(source_dir .. "/" .. rel)
    local dest = prefix .. rel
    local _, derr2 = ensure_dir(dest); if derr2 then return nil, derr2 end
    local _, werr = write_file(dest, data)
    if werr then return nil, "write " .. dest .. ": " .. tostring(werr) end
    written[#written + 1] = dest
  end

  local _, perr = db.put(mfst); if perr then return nil, perr end
  local _, rerr = record_installed(mfst, written); if rerr then return nil, rerr end
  return mfst
end

function M.verify(id)
  local mfst, derr = db.get(id); if not mfst then return nil, derr or "not installed" end
  local prefix = mfst.prefix or "/"
  local bad = {}
  for rel, meta in pairs(mfst.files) do
    local data = read_file(prefix .. rel)
    if not data then bad[#bad + 1] = rel .. " (missing)"
    else
      local digest = sha256.hex(data)
      if digest ~= meta.sha256:lower() then
        bad[#bad + 1] = rel .. " (sha mismatch)"
      end
    end
  end
  if #bad > 0 then return false, table.concat(bad, ", ") end
  return true
end

function M.uninstall(id)
  local root = db.root(); if not root then return nil, "no db root" end
  local installed_cfg = root .. "/" .. id .. "/installed.cfg"
  if not vfs.exists(installed_cfg) then return nil, "not installed" end

  local list_src = read_file(installed_cfg)
  local fn, e = load(list_src, "=installed.cfg", "t", {})
  if not fn then return nil, "cannot parse installed.cfg: " .. tostring(e) end
  local ok, list = pcall(fn)
  if not ok or type(list) ~= "table" then return nil, "bad installed.cfg" end

  for _, p in ipairs(list) do pcall(vfs.remove, p) end
  return db.remove(id)
end

return M
]])
W('/sys/lib/pkg/manifest.lua', [[
-- /sys/lib/pkg/manifest.lua — load and validate a package manifest.
--
-- A manifest is a Lua table returned from a chunk in <pkg>/manifest.cfg
-- with the schema described in docs/DESIGN.md §5.8. We accept the table
-- here, normalise defaults, and surface a structured error on any
-- problem so the installer can show the user a precise reason.

local M = {}

local semver = require("lib.codec.semver")
local vfs    = require("k.vfs")

local REQUIRED = { "id", "name", "version", "files" }

local function err(msg) return nil, "manifest: " .. msg end

function M.parse(src, source_name)
  local fn, lerr = load(src, "=" .. (source_name or "manifest"), "t", {})
  if not fn then return err("syntax: " .. lerr) end
  local ok, t = pcall(fn)
  if not ok then return err("evaluation: " .. tostring(t)) end
  if type(t) ~= "table" then return err("must return a table") end

  for _, k in ipairs(REQUIRED) do
    if t[k] == nil then return err("missing key: " .. k) end
  end

  local v, verr = semver.parse(t.version)
  if not v then return err(verr) end

  if type(t.files) ~= "table" or next(t.files) == nil then
    return err("files must be a non-empty table")
  end

  for path, meta in pairs(t.files) do
    if type(path) ~= "string" or path:sub(1, 1) == "/" then
      return err("file path must be relative: " .. tostring(path))
    end
    if type(meta) ~= "table" or type(meta.sha256) ~= "string" or #meta.sha256 ~= 64 then
      return err("file " .. path .. ": missing 64-char sha256")
    end
  end

  t.depends       = t.depends       or {}
  t.caps_required = t.caps_required or {}
  t.caps_optional = t.caps_optional or {}
  t.authors       = t.authors       or {}
  t.license       = t.license       or "unspecified"
  t.description   = t.description   or ""
  return t
end

function M.load_file(path)
  local src, e = vfs.read_all(path)
  if not src then return nil, "cannot read manifest: " .. tostring(e) end
  return M.parse(src, path)
end

local function fmt_key(k)
  if type(k) == "number" then return string.format("[%d]", k) end
  return string.format("[%q]", tostring(k))
end

function M.canonicalise(t)
  -- Stable Lua-table serialisation for hashing (and Ed25519 signing in M5).
  -- Keys are emitted in [...]=v form so any string is valid in the resulting
  -- table constructor.
  local lines = { "{" }
  local function emit(k, v, indent)
    indent = indent or "  "
    if type(v) == "string" then
      lines[#lines + 1] = string.format("%s%s = %q,", indent, fmt_key(k), v)
    elseif type(v) == "number" or type(v) == "boolean" then
      lines[#lines + 1] = string.format("%s%s = %s,", indent, fmt_key(k), tostring(v))
    elseif type(v) == "table" then
      local keys = {}
      for kk in pairs(v) do keys[#keys + 1] = kk end
      table.sort(keys, function(a, b) return tostring(a) < tostring(b) end)
      lines[#lines + 1] = string.format("%s%s = {", indent, fmt_key(k))
      for _, kk in ipairs(keys) do emit(kk, v[kk], indent .. "  ") end
      lines[#lines + 1] = indent .. "},"
    end
  end
  local keys = {}
  for k in pairs(t) do keys[#keys + 1] = k end
  table.sort(keys, function(a, b) return tostring(a) < tostring(b) end)
  for _, k in ipairs(keys) do emit(k, t[k]) end
  lines[#lines + 1] = "}"
  return table.concat(lines, "\n")
end

return M
]])
W('/sys/lib/pkg/registry.lua', [[
-- /sys/lib/pkg/registry.lua — remote package registry adapter.
--
-- A registry is a small HTTP-served directory laid out as:
--   <base>/index.cfg                  -- Lua table { id = "...", description = "..." }
--   <base>/<id>/<version>/manifest.cfg
--   <base>/<id>/<version>/payload.tar
--
-- We do NOT implement tar parsing in M5 — payloads are unpacked client-side
-- by the existing manifest-driven file copy if the registry serves the
-- payload as a flat directory tree under the version folder. So the layout
-- the loader actually needs is:
--   <base>/<id>/<version>/manifest.cfg
--   <base>/<id>/<version>/<file-listed-in-manifest.files>
-- and `pkg install <id>` stages every declared file via HTTP into a temp
-- directory, then hands the directory off to install.install_dir.

local M = {}

local vfs       = require("k.vfs")
local internet  = require("drv.internet")
local install   = require("lib.pkg.install")
local manifest  = require("lib.pkg.manifest")

local function http_get(url, opts)
  opts = opts or {}
  local body, status = internet.http_request(url, opts)
  if not body then return nil, status end
  if type(status) == "number" and (status < 200 or status >= 300) then
    return nil, "HTTP " .. tostring(status) .. " on " .. url
  end
  return body
end

function M.fetch_index(base_url)
  local body, err = http_get(base_url:gsub("/+$", "") .. "/index.cfg")
  if not body then return nil, err end
  local fn, lerr = load(body, "=index.cfg", "t", {})
  if not fn then return nil, "index syntax: " .. tostring(lerr) end
  local ok, t = pcall(fn)
  if not ok or type(t) ~= "table" then return nil, "index eval: " .. tostring(t) end
  return t
end

local function pkg_url(base, id, version, sub)
  return base:gsub("/+$", "") .. "/" .. id .. "/" .. version .. "/" .. sub
end

local function ensure_temp_root()
  for _, m in ipairs(vfs.mounts()) do
    if m.prefix:sub(1, 5) == "/mnt/" then
      local t = m.prefix .. "/var/tmp"
      pcall(vfs.mkdir, m.prefix .. "/var")
      pcall(vfs.mkdir, t)
      return t
    end
  end
end

local function ensure_dir(path)
  local parts, cur = {}, ""
  for p in path:gmatch("[^/]+") do parts[#parts + 1] = p end
  for i = 1, #parts - 1 do
    cur = cur .. "/" .. parts[i]
    if not vfs.exists(cur) then pcall(vfs.mkdir, cur) end
  end
end

function M.install(base_url, id, version, opts)
  -- Stage manifest + every declared file under a temp directory, then defer
  -- to install.install_dir which already does sha verification + DB writes.
  if not internet.has_internet() then return nil, "no internet" end

  local manifest_body, err = http_get(pkg_url(base_url, id, version, "manifest.cfg"))
  if not manifest_body then return nil, "manifest: " .. tostring(err) end
  local mfst, mferr = manifest.parse(manifest_body, "<remote>")
  if not mfst then return nil, mferr end
  if mfst.id ~= id then return nil, "manifest id mismatch: " .. mfst.id .. " vs " .. id end
  if mfst.version ~= version then return nil, "manifest version mismatch" end

  local tmp = ensure_temp_root(); if not tmp then return nil, "no temp root" end
  local stage = tmp .. "/pkg-" .. id:gsub("%W", "_") .. "-" .. version:gsub("%W", "_")
  pcall(vfs.mkdir, stage)
  vfs.write_all(stage .. "/manifest.cfg", manifest_body)

  for rel in pairs(mfst.files) do
    local body, ferr = http_get(pkg_url(base_url, id, version, rel))
    if not body then return nil, "fetch " .. rel .. ": " .. tostring(ferr) end
    ensure_dir(stage .. "/" .. rel)
    vfs.write_all(stage .. "/" .. rel, body)
  end

  return install.install_dir(stage, opts or {})
