-- /sys/lib/svc/manager.lua — service supervisor.
--
-- A service is a Lua program declared by a unit file in /etc/services. The
-- manager reads units, starts autostart services in dependency order, and
-- supervises them by subscribing to the proc.exit channel.
--
-- Unit format (Lua table returned from /etc/services/<id>.cfg):
--   {
--     id          = "logd",
--     description = "kernel log persister",
--     exec        = "/sys/svc/logd.lua",         -- script to run
--     args        = {},                          -- argv to the script
--     after       = { "other_id", ... },         -- deps (must be running)
--     caps        = { "syscall:write:/var/log/*", ... },
--     restart     = "always" | "on_failure" | "one_shot",
--     autostart   = true | false,
--     env         = { K = "V", ... },            -- shell-style env
--   }
--
-- State machine: loaded -> starting -> running -> stopping -> finished/failed.

local M = {}

local sched   = require("k.sched")
local exec    = require("k.exec")
local vfs     = require("k.vfs")
local ipc     = require("k.ipc")
local log     = require("k.log")
local stream  = require("std.stream")

local services           -- { id -> service_record }
local proc_exit_handle
local pid_to_id          -- { pid -> service_id }

local DEFAULT_RESTART = "on_failure"

-- ---- helpers ------------------------------------------------------------

local function load_unit(path)
  local src, err = vfs.read_all(path)
  if not src then return nil, err end
  local fn, lerr = load(src, "=" .. path, "t", {})
  if not fn then return nil, lerr end
  local ok, t = pcall(fn)
  if not ok then return nil, tostring(t) end
  if type(t) ~= "table" or not t.id or not t.exec then
    return nil, "unit missing id or exec"
  end
  t.restart   = t.restart   or DEFAULT_RESTART
  t.after     = t.after     or {}
  t.caps      = t.caps      or {}
  t.args      = t.args      or {}
  t.env       = t.env       or {}
  t.autostart = t.autostart ~= false                -- default true
  return t
end

function M.load_units(dir)
  services = services or {}
  pid_to_id = pid_to_id or {}
  if not vfs.isdir(dir) then return 0 end
  local entries = vfs.list(dir) or {}
  local count = 0
  for _, name in ipairs(entries) do
    if name:sub(-4) == ".cfg" then
      local unit, err = load_unit(dir .. "/" .. name)
      if unit then
        services[unit.id] = services[unit.id] or { unit = unit, state = "loaded", restart_count = 0 }
        services[unit.id].unit = unit
        count = count + 1
      else
        log.warn("svc", "unit " .. name .. ": " .. tostring(err))
      end
    end
  end
  return count
end

local function topo_sort(ids)
  -- Kahn's algorithm. `after` declares a strict happens-before edge.
  local in_deg, edges_to = {}, {}
  for _, id in ipairs(ids) do in_deg[id] = 0; edges_to[id] = {} end
  for _, id in ipairs(ids) do
    for _, dep in ipairs(services[id].unit.after) do
      if services[dep] then
        edges_to[dep][#edges_to[dep] + 1] = id
        in_deg[id] = in_deg[id] + 1
      end
    end
  end
  local order, queue = {}, {}
  for _, id in ipairs(ids) do if in_deg[id] == 0 then queue[#queue + 1] = id end end
  while #queue > 0 do
    local id = table.remove(queue, 1)
    order[#order + 1] = id
    for _, succ in ipairs(edges_to[id]) do
      in_deg[succ] = in_deg[succ] - 1
      if in_deg[succ] == 0 then queue[#queue + 1] = succ end
    end
  end
  if #order ~= #ids then
    return nil, "service dependency cycle detected"
  end
  return order
end

local function spawn_service(id)
  local svc = services[id]
  if not svc then return nil, "no such service: " .. id end
  if svc.state == "running" or svc.state == "starting" then return svc end
  svc.state = "starting"
  local p, err = exec.exec(svc.unit.exec, svc.unit.args, {
    streams   = { stdin = stream.null(), stdout = stream.null(), stderr = stream.null() },
    shell_env = svc.unit.env,
    cmdline   = "[" .. id .. "]",
    name      = "svc:" .. id,
    caps      = svc.unit.caps,
  })
  if not p then
    svc.state = "failed"
    svc.last_error = err
    log.error("svc", "start " .. id .. ": " .. tostring(err))
    ipc.publish("svc.evt", { id = id, state = "failed", reason = err })
    return nil, err
  end
  svc.state = "running"
  svc.pid = p.id
  svc.started_at = computer.uptime()
  pid_to_id[p.id] = id
  log.info("svc", "started " .. id .. " (pid=" .. p.id .. ")")
  ipc.publish("svc.evt", { id = id, state = "running", pid = p.id })
  return svc
end

function M.start(id)
  local svc = services[id]
  if not svc then return nil, "no such service: " .. id end
  for _, dep in ipairs(svc.unit.after) do
    if services[dep] and services[dep].state ~= "running" then
      local ok, err = M.start(dep)
      if not ok then return nil, "dep " .. dep .. " failed: " .. tostring(err) end
    end
  end
  return spawn_service(id)
end

function M.stop(id)
  local svc = services[id]
  if not svc or not svc.pid then return nil, "service not running" end
  -- Cooperative stop: publish a stop request on a per-service channel and
  -- wait for the proc to exit. Services are expected to subscribe and exit
  -- voluntarily; the supervisor doesn't have a kill primitive (OC has no
  -- preemption), so a stuck service must be addressed via shutdown/reboot.
  svc.state = "stopping"
  ipc.publish("svc.stop." .. id, true)
  local res = sched.wait_pid(svc.pid, 5)
  if not res then
    svc.state = "running"
    return nil, "service did not exit within 5s"
  end
  return true
end

function M.list()
  local out = {}
  for id, svc in pairs(services or {}) do
    out[#out + 1] = {
      id           = id,
      description  = svc.unit.description,
      state        = svc.state,
      pid          = svc.pid,
      restart_count = svc.restart_count,
      started_at   = svc.started_at,
      last_error   = svc.last_error,
    }
  end
  table.sort(out, function(a, b) return a.id < b.id end)
  return out
end

function M.status(id)
  local svc = services and services[id]
  if not svc then return nil end
  return {
    id            = id,
    description   = svc.unit.description,
    state         = svc.state,
    pid           = svc.pid,
    restart_count = svc.restart_count,
    started_at    = svc.started_at,
    last_error    = svc.last_error,
    unit          = svc.unit,
  }
end

local function on_proc_exit(payload)
  local id = pid_to_id[payload.id]
  if not id then return end
  pid_to_id[payload.id] = nil
  local svc = services[id]; if not svc then return end
  svc.pid = nil
  log.info("svc", id .. " exited code=" .. tostring(payload.code))
  if svc.state == "stopping" then
    svc.state = "finished"
    ipc.publish("svc.evt", { id = id, state = "finished", code = payload.code })
    return
  end
  local policy = svc.unit.restart
  local should_restart =
    policy == "always" or
    (policy == "on_failure" and (payload.code or 0) ~= 0)
  if should_restart and svc.restart_count < 10 then
    svc.restart_count = svc.restart_count + 1
    local delay = math.min(8, 1 * 2 ^ math.min(svc.restart_count - 1, 3))
    log.warn("svc", id .. " will restart in " .. delay .. "s (count=" ..
      svc.restart_count .. ")")
    sched.spawn(function()
      sched.sleep(delay)
      spawn_service(id)
    end, { name = "svc-restart:" .. id, caps = { "*" } })
  else
    svc.state = (payload.code or 0) == 0 and "finished" or "failed"
    svc.last_error = payload.reason
    ipc.publish("svc.evt", { id = id, state = svc.state, code = payload.code })
  end
end

function M.start_all_autostart(unit_dir)
  M.load_units(unit_dir)
  local ids = {}
  for id, svc in pairs(services) do
    if svc.unit.autostart then ids[#ids + 1] = id end
  end
  local order, err = topo_sort(ids)
  if not order then return nil, err end
  for _, id in ipairs(order) do
    local ok, e = spawn_service(id)
    if not ok then log.error("svc", "autostart " .. id .. " failed: " .. tostring(e)) end
  end
  return order
end

function M.bind_supervisor()
  if proc_exit_handle then return end
  proc_exit_handle = ipc.subscribe("proc.exit", on_proc_exit)
end

return M
]])
W('/sys/lib/term/console.lua', [[
-- /sys/lib/term/console.lua — single-screen text terminal.
--
-- Owns the cursor, handles line wrapping, scrolling, colours, and a
-- blocking line editor that consumes keyboard events from the IPC bus.
--
-- Public API:
--   console.init()                                set up cursor + colours
--   console.write(s)                              write text at the cursor
--   console.writeln(s?)                           write + newline
--   console.clear()                               clear and home cursor
--   console.set_fg(rgb), console.set_bg(rgb)
--   console.fg(), console.bg()                    current colour
--   console.cursor() -> x, y                      current cursor
--   console.set_cursor(x, y)
--   console.size() -> w, h                        usable area
--   console.read_line(prompt?, opts?) -> string   blocks for ENTER

local M = {}

local sched   = require("k.sched")
local ipc     = require("k.ipc")
local gpu     = require("drv.gpu")
local keymap  = require("lib.term.keymap")

local cur_x, cur_y
local fg, bg

local function size() return gpu.size() end

local function scroll_up(n)
  n = n or 1
  local w, h = size()
  if not w or w <= 0 or h <= 0 then return end
  if n >= h then gpu.fill(1, 1, w, h, " "); cur_y = 1; return end
  gpu.copy(1, 1 + n, w, h - n, 0, -n)
  gpu.fill(1, h - n + 1, w, n, " ")
  cur_y = cur_y - n
end

local function newline()
  cur_x = 1
  cur_y = cur_y + 1
  local _, h = size()
  if h and cur_y > h then scroll_up(cur_y - h) end
end

function M.init()
  fg, bg = 0xCCCCCC, 0x000000
  cur_x, cur_y = 1, 1
  gpu.set_fg(fg); gpu.set_bg(bg)
  gpu.clear()
end

function M.size() return size() end
function M.fg() return fg end
function M.bg() return bg end
function M.set_fg(c) fg = c; gpu.set_fg(c) end
function M.set_bg(c) bg = c; gpu.set_bg(c) end
function M.cursor() return cur_x, cur_y end
function M.set_cursor(x, y) cur_x, cur_y = x, y end

function M.clear() gpu.clear(); cur_x, cur_y = 1, 1 end

function M.write(s)
  s = tostring(s)
  local w, h = size()
  if not w or w <= 0 or not h or h <= 0 then return end
  for piece in s:gmatch("[^\n]*\n?") do
    if piece == "" then break end
    local has_nl = piece:sub(-1) == "\n"
    local body = has_nl and piece:sub(1, -2) or piece
    while #body > 0 do
      local space = w - cur_x + 1
      if space <= 0 then
        newline()
        space = w - cur_x + 1
        if space <= 0 then break end
      end
      local chunk = body:sub(1, space)
      gpu.set(cur_x, cur_y, chunk)
      cur_x = cur_x + #chunk
      body = body:sub(#chunk + 1)
    end
    if has_nl then newline() end
  end
end

function M.writeln(s) M.write((s or "") .. "\n") end

-- ---- line editor --------------------------------------------------------
-- A blocking line editor that reads keyboard events from the IPC bus.
-- Supports printable characters, Home/End, Left/Right, Backspace/Delete,
-- history (Up/Down) and clipboard paste. Multi-line wrapping inside the
-- editor is not supported — long inputs simply scroll horizontally past the
-- right edge; visual selection and kill-ring are GUI-widget territory.

local history = { entries = {}, pos = nil }

local function key_filter(name)
  return name == "key_down" or name == "clipboard"
end

function M.read_line(prompt, opts)
  opts = opts or {}
  prompt = prompt or ""
  M.write(prompt)
  local _, sy = M.cursor()
  local prompt_len = M.cursor() - 1                -- column where buffer starts
  local buf, cur = {}, 0
  history.pos = nil

  local function repaint()
    local w = size()
    if not w or w <= 0 then return end
    gpu.fill(prompt_len + 1, sy, w - prompt_len, 1, " ")
    local s = table.concat(buf)
    gpu.set(prompt_len + 1, sy, s)
    cur_x = prompt_len + 1 + cur
    cur_y = sy
  end

  while true do
    local ev = sched.wait(key_filter)
    if ev and ev.name == "key_down" then
      local _, char, code = ev.args[1], ev.args[2], ev.args[3]
      local action = keymap.action(code, char)
      if action == "enter" then
        M.set_cursor(prompt_len + 1 + #buf, sy)
        M.write("\n")
        local out = table.concat(buf)
        if out ~= "" then history.entries[#history.entries + 1] = out end
        return out
      elseif action == "backspace" then
        if cur > 0 then table.remove(buf, cur); cur = cur - 1; repaint() end
      elseif action == "delete" then
        if cur < #buf then table.remove(buf, cur + 1); repaint() end
      elseif action == "left" then
        if cur > 0 then cur = cur - 1; cur_x = prompt_len + 1 + cur end
      elseif action == "right" then
        if cur < #buf then cur = cur + 1; cur_x = prompt_len + 1 + cur end
      elseif action == "home" then
        cur = 0; cur_x = prompt_len + 1
      elseif action == "end" then
        cur = #buf; cur_x = prompt_len + 1 + cur
      elseif action == "up" or action == "down" then
        local n = #history.entries
        if n > 0 then
          history.pos = history.pos or n + 1
          history.pos = action == "up"
            and math.max(1, history.pos - 1)
            or  math.min(n + 1, history.pos + 1)
          local entry = history.entries[history.pos] or ""
          buf = {}
          for i = 1, #entry do buf[i] = entry:sub(i, i) end
          cur = #buf
          repaint()
        end
      elseif action == "interrupt" then
        M.write("\n")
        return nil
      elseif char and char >= 32 and char < 127 then
        cur = cur + 1
        table.insert(buf, cur, string.char(char))
        repaint()
      elseif char and char >= 128 then
        local u = _G.unicode
        local glyph = u and u.char and u.char(char) or nil
        if glyph then
          cur = cur + 1
          table.insert(buf, cur, glyph)
          repaint()
        end
      end
    elseif ev and ev.name == "clipboard" then
      local _, text = ev.args[1], ev.args[2]
      if text then
        for ch in text:gmatch("[^\n]+") do
          for i = 1, #ch do
            cur = cur + 1
            table.insert(buf, cur, ch:sub(i, i))
          end
        end
        repaint()
        if text:find("\n", 1, true) then
          M.set_cursor(prompt_len + 1 + #buf, sy)
          M.write("\n")
          local out = table.concat(buf)
          if out ~= "" then history.entries[#history.entries + 1] = out end
          return out
        end
      end
    end
  end
end

function M.history() return history.entries end

return M
]])
W('/sys/lib/term/keymap.lua', [[
-- /sys/lib/term/keymap.lua — translates LWJGL key codes into editor actions.
--
-- The console's line editor and the M3 widgets both consume the same
-- action-name dictionary. Keep this list explicit; keys not listed here
-- fall through to the printable-character path.

local M = {}

local CODE_TO_ACTION = {
  [28]  = "enter",
  [156] = "enter",                                 -- numpad enter
  [14]  = "backspace",
  [211] = "delete",
  [203] = "left",
  [205] = "right",
  [200] = "up",
  [208] = "down",
  [199] = "home",
  [207] = "end",
  [15]  = "tab",
  [1]   = "interrupt",                             -- Esc, treated as cancel
}

local CHAR_TO_ACTION = {
  [3]  = "interrupt",                              -- Ctrl-C
  [4]  = "eof",                                    -- Ctrl-D
}

function M.action(code, char)
  return CODE_TO_ACTION[code] or CHAR_TO_ACTION[char]
end

return M
]])
W('/sys/lib/term/tty.lua', [[
-- /sys/lib/term/tty.lua — Stream interface over the interactive console.
--
-- One TTY pair per console is enough; we expose a singleton via
-- `tty.stdin()` / `tty.stdout()` / `tty.stderr()` that the init service hands
-- to the first shell. Subprocesses can ask for fresh streams if they want
-- to render to a sub-region (the M3 compositor will use that).

local M = {}

local stream  = require("std.stream")
local console = require("lib.term.console")
local sched   = require("k.sched")

local function make_stdout(color)
  local original
  return stream.new {
    _write = function(self, s)
      if color then original = console.fg(); console.set_fg(color) end
      console.write(s)
      if color then console.set_fg(original) end
      return self
    end,
    _flush = function(self) return self end,
  }
end

local _stdin
local function get_stdin()
  if _stdin then return _stdin end
  _stdin = stream.new {
    _read = function(self, fmt_or_n)
      -- Lines are the only format the live keyboard meaningfully produces.
      if type(fmt_or_n) == "number" then
        local line = console.read_line()
        if not line then return nil end
        return line:sub(1, fmt_or_n)
      end
      return console.read_line()
    end,
  }
  return _stdin
end

function M.stdin()  return get_stdin() end
function M.stdout() return make_stdout(nil) end
function M.stderr() return make_stdout(0xFF6060) end                       -- red

return M
]])
W('/sys/lib/ui/buffer.lua', [[
-- /sys/lib/ui/buffer.lua — Lua-level virtual cell buffer.
--
-- The compositor writes into a Buffer and then asks it to flush against a
-- GPU. Flush walks every cell, compares with the previous frame and emits
-- minimal gpu.set/gpu.fill calls — runs of identical (fg, bg) cells become
-- one gpu.set, and rectangles of identical (ch, fg, bg) become one gpu.fill.
--
-- This matches what OpenComputers' per-tick GPU op budget rewards: never
-- repaint cells that didn't change, and batch what does change by colour.

local M = {}

local Buffer = {}
Buffer.__index = Buffer

local function clear_arr(a, n, v)
  for i = 1, n do a[i] = v end
end

function M.new(w, h)
  local self = setmetatable({}, Buffer)
  self:resize(w, h)
  return self
end

function Buffer:resize(w, h)
  self.w, self.h = w, h
  self.n = w * h
  self.cur_ch, self.cur_fg, self.cur_bg = {}, {}, {}
  self.prev_ch, self.prev_fg, self.prev_bg = {}, {}, {}
  clear_arr(self.cur_ch, self.n, " ")
  clear_arr(self.cur_fg, self.n, 0xCCCCCC)
  clear_arr(self.cur_bg, self.n, 0x000000)
  -- Sentinels: nothing matches, forcing a full repaint on the first flush.
  clear_arr(self.prev_ch, self.n, false)
  clear_arr(self.prev_fg, self.n, -1)
  clear_arr(self.prev_bg, self.n, -1)
end

function Buffer:size() return self.w, self.h end

local function index(self, x, y)
  if x < 1 or y < 1 or x > self.w or y > self.h then return nil end
  return (y - 1) * self.w + x
end

function Buffer:set(x, y, ch, fg, bg)
  local idx = index(self, x, y); if not idx then return end
  self.cur_ch[idx] = ch
  self.cur_fg[idx] = fg
  self.cur_bg[idx] = bg
end

function Buffer:fill(x, y, w, h, ch, fg, bg)
  local x2, y2 = math.min(self.w, x + w - 1), math.min(self.h, y + h - 1)
  if x > self.w or y > self.h then return end
  if x < 1 then x = 1 end
  if y < 1 then y = 1 end
  for yy = y, y2 do
    local base = (yy - 1) * self.w
    for xx = x, x2 do
      self.cur_ch[base + xx] = ch
      self.cur_fg[base + xx] = fg
      self.cur_bg[base + xx] = bg
    end
  end
end

function Buffer:get(x, y)
  local idx = index(self, x, y); if not idx then return nil end
  return self.cur_ch[idx], self.cur_fg[idx], self.cur_bg[idx]
end

local function commit_run(gpu, x, y, run, fg, bg)
  if #run == 0 then return end
  gpu.set_fg(fg)
  gpu.set_bg(bg)
  gpu.set(x, y, table.concat(run))
end

function Buffer:flush(gpu)
  -- Emit minimal gpu ops to bring the screen in sync with the current frame.
  -- We don't currently coalesce vertical fills; horizontal is the common
  -- case and the test suite will reveal where we need vertical coalescing.
  for y = 1, self.h do
    local base = (y - 1) * self.w
    local x = 1
    while x <= self.w do
      local i = base + x
      local cur_ch, cur_fg, cur_bg = self.cur_ch[i], self.cur_fg[i], self.cur_bg[i]
      if self.prev_ch[i] == cur_ch and self.prev_fg[i] == cur_fg and self.prev_bg[i] == cur_bg then
        x = x + 1
      else
        local run = { cur_ch }
        local rx, fg, bg = x, cur_fg, cur_bg
        self.prev_ch[i], self.prev_fg[i], self.prev_bg[i] = cur_ch, cur_fg, cur_bg
        x = x + 1
        while x <= self.w do
          local j = base + x
          local jch, jfg, jbg = self.cur_ch[j], self.cur_fg[j], self.cur_bg[j]
          if jfg == fg and jbg == bg
             and not (self.prev_ch[j] == jch and self.prev_fg[j] == jfg and self.prev_bg[j] == jbg) then
            run[#run + 1] = jch
            self.prev_ch[j], self.prev_fg[j], self.prev_bg[j] = jch, jfg, jbg
            x = x + 1
          else break end
        end
        commit_run(gpu, rx, y, run, fg, bg)
      end
    end
  end
end

function Buffer:invalidate()
  -- Force the next flush to behave as if every cell changed.
  for i = 1, self.n do
    self.prev_ch[i], self.prev_fg[i], self.prev_bg[i] = false, -1, -1
  end
end

return M
]])
W('/sys/lib/ui/compositor.lua', [[
-- /sys/lib/ui/compositor.lua — workspace + render loop.
--
-- A compositor owns:
--   * one `Buffer` sized to the active GPU resolution
--   * one root widget (the workspace) holding the desktop + windows
--   * an event subscription chain (kbd.key, oc.signal.touch, …)
--
-- The render loop wakes whenever a widget marks itself dirty or whenever an
-- input event arrives. It calls `:layout()` if the bounds changed, then
-- walks the tree's `:draw()` and finally `Buffer:flush(gpu)` to emit the
-- minimum number of GPU ops required to bring the screen up to date.

local M = {}

local sched   = require("k.sched")
local ipc     = require("k.ipc")
local log     = require("k.log")
local gpu     = require("drv.gpu")
local Buffer  = require("lib.ui.buffer")
local widget  = require("lib.ui.widget")
local theme_m = require("lib.ui.theme")
local event   = require("lib.ui.event")

local Compositor = {}
Compositor.__index = Compositor

function M.new(opts)
  opts = opts or {}
  local w, h = gpu.size()
  if not w or w <= 0 or not h or h <= 0 then
    return nil, "compositor requires an active GPU"
  end
  local self = setmetatable({
    buffer       = Buffer.new(w, h),
    theme        = opts.theme or theme_m.current(),
    root         = widget.new("workspace", { _layout_children = function(s)
                     for _, c in ipairs(s.children) do c:layout(s.bounds.x, s.bounds.y, s.bounds.w, s.bounds.h) end
                   end }),
    dirty        = true,
    stop         = false,
    handlers     = {},
    queue        = {},
  }, Compositor)
  self.root:layout(1, 1, w, h)
  self.root:invalidate()
  return self
end

function Compositor:add(widget_obj)
  self.root:add_child(widget_obj)
  widget_obj:layout(self.root.bounds.x, self.root.bounds.y, self.root.bounds.w, self.root.bounds.h)
  if widget_obj._layout_children then widget_obj:_layout_children() end
  return widget_obj
end

function Compositor:set_theme(theme)
  self.theme = theme
  self.buffer:invalidate()
  self.dirty = true
end

local function any_dirty(node)
  if node.dirty then return true end
  for _, c in ipairs(node.children) do if any_dirty(c) then return true end end
  return false
end

function Compositor:render()
  if not (self.dirty or any_dirty(self.root)) then return end
  self.root:draw(self.buffer, self.theme)
  self.buffer:flush(gpu)
  self.dirty = false
end

function Compositor:dispatch(ev)
  -- Walk into root; let widgets claim the event. Always render afterwards
  -- since event handlers commonly call :invalidate().
  self.root:on_event(ev)
  self:render()
end

local TICK = "__ui_tick"

local function enqueue(self, ev)
  self.queue[#self.queue + 1] = ev
  computer.pushSignal(TICK)
end

local function wire_inputs(self)
  -- Subscribers translate raw IPC payloads into typed events and enqueue
  -- them. The render loop drains the queue, so all rendering happens in a
  -- single coroutine context — no double-paints from concurrent subscribers.
  self.handlers[#self.handlers + 1] = ipc.subscribe("kbd.key", function(p)
    enqueue(self, event.key(p.down, p.char, p.code, p.mods, p.player))
  end)
  self.handlers[#self.handlers + 1] = ipc.subscribe("kbd.paste", function(p)
    enqueue(self, event.paste(p.value, p.player))
  end)

  for raw, factory in pairs({
    ["oc.signal.touch"]  = function(a) return event.touch(a[2], a[3], a[4], a[5]) end,
    ["oc.signal.drag"]   = function(a) return event.drag(a[2], a[3], a[4], a[5]) end,
    ["oc.signal.drop"]   = function(a) return event.drop(a[2], a[3], a[4], a[5]) end,
    ["oc.signal.scroll"] = function(a) return event.scroll(a[2], a[3], a[4], a[5]) end,
    ["oc.signal.screen_resized"] = function(a) return event.resize(a[2], a[3]) end,
  }) do
    self.handlers[#self.handlers + 1] = ipc.subscribe(raw, function(args)
      enqueue(self, factory(args))
    end)
  end
end

function Compositor:run()
  wire_inputs(self)
  self:render()
  while not self.stop do
    sched.wait(function(name) return name == TICK end, 1)
    while #self.queue > 0 do
      local ev = table.remove(self.queue, 1)
      if ev.type == "resize" then
        self.buffer:resize(ev.w, ev.h)
        self.root:layout(1, 1, ev.w, ev.h)
        self.root:invalidate()
      end
      self.root:on_event(ev)
    end
    self:render()
  end
  for _, h in ipairs(self.handlers) do ipc.unsubscribe(h) end
end

function Compositor:request_stop() self.stop = true; computer.pushSignal(TICK) end

function Compositor:size() return self.buffer:size() end
function Compositor:invalidate() self.dirty = true; self.buffer:invalidate() end

M.Compositor = Compositor
return M
]])
