-- /sys/lib/ui/widgets/checkbox.lua — labelled binary toggle.
local widget = require("lib.ui.widget")

local function ucs_len(s) local u = _G.unicode; return u and u.len and u.len(s) or #s end

return function(props)
  return widget.new("checkbox", {
    state = { checked = props.checked == true },

    measure = function(self, max_w, max_h)
      local label = self.props.text or ""
      return math.min(4 + ucs_len(label), max_w), 1
    end,

    draw = function(self, buffer, theme)
      local b = self.bounds
      local t = theme.checkbox or {}
      local fg = t.fg or theme.palette.fg
      local accent = t.accent or theme.palette.accent
      local bg = self.props.bg or theme.palette.bg
      buffer:fill(b.x, b.y, b.w, b.h, " ", fg, bg)
      buffer:set(b.x, b.y, "[", fg, bg)
      buffer:set(b.x + 1, b.y, self.state.checked and "x" or " ",
                 self.state.checked and accent or fg, bg)
      buffer:set(b.x + 2, b.y, "]", fg, bg)
      local text = self.props.text or ""
      for i = 1, math.min(ucs_len(text), b.w - 4) do
        buffer:set(b.x + 3 + i, b.y, text:sub(i, i), fg, bg)
      end
      self.dirty = false
    end,

    on_event = function(self, ev)
      if ev.type == "drop" and self:hit(ev.x, ev.y) then
        self.state.checked = not self.state.checked
        if self.props.on_toggle then self.props.on_toggle(self, self.state.checked) end
        self:invalidate(); return true
      end
      return false
    end,
  }, props)
end
]])
W('/sys/lib/ui/widgets/clock.lua', [[
-- /sys/lib/ui/widgets/clock.lua — live-updating clock label.
--
-- The clock invalidates itself once per second via a synthetic "__clock_tick"
-- signal so the compositor's render loop re-paints it. Keeps display in
-- sync without an animation framework.

local widget = require("lib.ui.widget")
local sched  = require("k.sched")
local ipc    = require("k.ipc")

local function format_clock()
  -- OS uptime → HH:MM:SS for in-game time. The OC computer.realTime() gives
  -- wall time; we use that so the player's clock matches the real world.
  local t = math.floor(computer.realTime() or computer.uptime())
  local h = math.floor(t / 3600) % 24
  local m = math.floor(t / 60) % 60
  local s = t % 60
  return string.format("%02d:%02d:%02d", h, m, s)
end

local installed_tick = false
local function ensure_tick()
  if installed_tick then return end
  installed_tick = true
  sched.spawn(function()
    while true do
      sched.sleep(1)
      ipc.publish("clock.tick", {})
      computer.pushSignal("__ui_tick")
    end
  end, { name = "clock-ticker", caps = { "*" } })
end

return function(props)
  ensure_tick()
  local w = widget.new("clock", {
    measure = function(_, max_w, max_h) return math.min(8, max_w), 1 end,
    draw = function(self, buffer, theme)
      local text = format_clock()
      local b = self.bounds
      local fg = self.props.fg or (theme.taskbar and theme.taskbar.fg) or theme.palette.fg
      local bg = self.props.bg or (theme.taskbar and theme.taskbar.bg) or theme.palette.bg
      buffer:fill(b.x, b.y, b.w, 1, " ", fg, bg)
      for i = 1, math.min(#text, b.w) do
        buffer:set(b.x + i - 1, b.y, text:sub(i, i), fg, bg)
      end
      self.dirty = false
    end,
  }, props or {})
  ipc.subscribe("clock.tick", function() w:invalidate() end)
  return w
end
]])
