-- /sys/lib/ui/widgets/list.lua — vertical scrollable list.
local widget = require("lib.ui.widget")

local function ucs_len(s) local u = _G.unicode; return u and u.len and u.len(s) or #s end
local function ucs_sub(s, a, b) local u = _G.unicode; return u and u.sub and u.sub(s, a, b) or s:sub(a, b) end

return function(props)
  return widget.new("list", {
    state = { selected = props.selected or 1, scroll = 0 },

    measure = function(self, max_w, max_h)
      return math.min(self.props.width or max_w, max_w),
             math.min(self.props.height or #(self.props.items or {}), max_h)
    end,

    draw = function(self, buffer, theme)
      local b = self.bounds
      local t = theme.list or {}
      local bg = t.bg or theme.palette.surface
      local fg = t.fg or theme.palette.fg
      buffer:fill(b.x, b.y, b.w, b.h, " ", fg, bg)
      local items = self.props.items or {}
      for row = 0, b.h - 1 do
        local idx = row + 1 + self.state.scroll
        local item = items[idx]
        if item then
          local label = self.props.format and self.props.format(item) or tostring(item)
          local row_fg, row_bg = fg, bg
          if idx == self.state.selected then
            row_fg = t.selected_fg or 0xFFFFFF
            row_bg = t.selected_bg or theme.palette.accent
          end
          buffer:fill(b.x, b.y + row, b.w, 1, " ", row_fg, row_bg)
          local n = math.min(ucs_len(label), b.w)
          for i = 1, n do
            buffer:set(b.x + i - 1, b.y + row, ucs_sub(label, i, i), row_fg, row_bg)
          end
        end
      end
      self.dirty = false
    end,

    on_event = function(self, ev)
      local items = self.props.items or {}
      if ev.type == "touch" and self:hit(ev.x, ev.y) then
        local idx = ev.y - self.bounds.y + 1 + self.state.scroll
        if items[idx] then
          self.state.selected = idx
          if self.props.on_select then self.props.on_select(self, items[idx], idx) end
          self:invalidate(); return true
        end
      end
      if ev.type == "scroll" and self:hit(ev.x, ev.y) then
        local max_scroll = math.max(0, #items - self.bounds.h)
        self.state.scroll = math.max(0, math.min(max_scroll, self.state.scroll - ev.dir))
        self:invalidate(); return true
      end
      if ev.type == "key" and ev.down and self.state.focused then
        if ev.code == 200 then  -- up
          self.state.selected = math.max(1, self.state.selected - 1)
          if self.state.selected - 1 < self.state.scroll then self.state.scroll = self.state.selected - 1 end
          self:invalidate(); return true
        elseif ev.code == 208 then  -- down
          self.state.selected = math.min(#items, self.state.selected + 1)
          if self.state.selected > self.state.scroll + self.bounds.h then
            self.state.scroll = self.state.selected - self.bounds.h
          end
          self:invalidate(); return true
        elseif ev.code == 28 then  -- enter
          if self.props.on_activate and items[self.state.selected] then
            self.props.on_activate(self, items[self.state.selected], self.state.selected)
          end
          return true
        end
      end
      return false
    end,
  }, props)
end
]])
W('/sys/lib/ui/widgets/menu.lua', [[
-- /sys/lib/ui/widgets/menu.lua — pop-up menu of actions.
local widget = require("lib.ui.widget")
local function ucs_len(s) local u = _G.unicode; return u and u.len and u.len(s) or #s end

return function(props)
  return widget.new("menu", {
    state = { hover = nil },

    measure = function(self, max_w, max_h)
      local items = self.props.items or {}
      local w = 0
      for _, it in ipairs(items) do w = math.max(w, ucs_len(it.label)) end
      return math.min(w + 2, max_w), math.min(#items, max_h)
    end,

    draw = function(self, buffer, theme)
      local b = self.bounds
      local t = theme.menu or {}
      local bg = t.bg or theme.palette.surface
      local fg = t.fg or theme.palette.fg
      buffer:fill(b.x, b.y, b.w, b.h, " ", fg, bg)
      for i, it in ipairs(self.props.items or {}) do
        if i > b.h then break end
        local rfg, rbg = fg, bg
        if i == self.state.hover then
          rfg, rbg = t.hover_fg or 0xFFFFFF, t.hover_bg or theme.palette.accent
        end
        buffer:fill(b.x, b.y + i - 1, b.w, 1, " ", rfg, rbg)
        local n = math.min(ucs_len(it.label), b.w - 1)
        for j = 1, n do buffer:set(b.x + j, b.y + i - 1, it.label:sub(j, j), rfg, rbg) end
      end
      self.dirty = false
    end,

    on_event = function(self, ev)
      if not self:hit(ev.x or -1, ev.y or -1) and ev.type ~= "key" then
        if ev.type == "drop" or ev.type == "touch" then
          if self.props.on_close then self.props.on_close(self) end
          return false
        end
      end
      if ev.type == "drag" or ev.type == "touch" then
        local idx = ev.y - self.bounds.y + 1
        local items = self.props.items or {}
        if items[idx] then
          self.state.hover = idx; self:invalidate()
          if ev.type == "touch" then return true end
        end
      end
      if ev.type == "drop" and self:hit(ev.x, ev.y) then
        local idx = ev.y - self.bounds.y + 1
        local item = (self.props.items or {})[idx]
        if item and item.action then item.action(self) end
        if self.props.on_close then self.props.on_close(self) end
        return true
      end
      return false
    end,
  }, props)
end
]])
W('/sys/lib/ui/widgets/terminal.lua', [[
-- /sys/lib/ui/widgets/terminal.lua — embedded interactive terminal.
--
-- Owns three stream endpoints suitable for handing to exec.exec():
--   .stdin  — Stream<read> that blocks until the user types a line + Enter
--   .stdout — Stream<write> that the hosted process writes to
--   .stderr — Stream<write> in red
--
-- Internally maintains a scrollback array. Keystrokes routed to the widget
-- accumulate into a current input line; pressing Enter flushes that line
-- (with a trailing "\n") onto the stdin pipe and echoes it.

local widget = require("lib.ui.widget")
local pipe   = require("std.pipe")
local stream = require("std.stream")
local sched  = require("k.sched")

local function ucs_char(c) local u = _G.unicode; return u and u.char and u.char(c) or string.char(c) end

return function(props)
  local stdin_r, stdin_w = pipe.new()
  local self = widget.new("terminal", {}, props or {})
  -- Scrollback: each entry is { text=string, fg=int, bg=int } and represents
  -- a logical line. We split incoming bytes on "\n".
  self.state.lines    = { { text = "", fg = nil, bg = nil } }
  self.state.input    = ""
  self.state.input_col = 0
  self.state.scroll   = 0

  local function append(s, fg)
    local cur = self.state.lines[#self.state.lines]
    local i, n = 1, #s
    while i <= n do
      local nl = s:find("\n", i, true)
      if not nl then
        cur.text = cur.text .. s:sub(i)
        if fg then cur.fg = fg end
        i = n + 1
      else
        cur.text = cur.text .. s:sub(i, nl - 1)
        if fg then cur.fg = fg end
        self.state.lines[#self.state.lines + 1] = { text = "", fg = nil, bg = nil }
        cur = self.state.lines[#self.state.lines]
        i = nl + 1
      end
    end
    self:invalidate()
    computer.pushSignal("__ui_tick")
  end

  self.stdout = stream.new {
    _write = function(s, txt) append(txt, nil); return s end,
  }
  self.stderr = stream.new {
    _write = function(s, txt) append(txt, 0xE05050); return s end,
  }
  self.stdin  = stdin_r
  local stdin_writer = stdin_w

  self.measure = function(_, max_w, max_h) return max_w, max_h end

  self.draw = function(self_, buffer, theme)
    local b = self_.bounds
    local fg_default = theme.palette.fg
    local bg_default = theme.palette.bg
    buffer:fill(b.x, b.y, b.w, b.h, " ", fg_default, bg_default)
    -- Render the last `b.h - 1` lines (leaving the last row for the input).
    local visible_rows = b.h - 1
    local total = #self_.state.lines
    local first = math.max(1, total - visible_rows + 1 - self_.state.scroll)
    for row = 0, visible_rows - 1 do
      local entry = self_.state.lines[first + row]
      if entry then
        local fg = entry.fg or fg_default
        local text = entry.text:sub(1, b.w)
        for i = 1, #text do
          buffer:set(b.x + i - 1, b.y + row, text:sub(i, i), fg, bg_default)
        end
      end
    end
    -- Input line at the bottom with a leading prompt-marker so the user
    -- always sees their cursor even before the shell has emitted a prompt.
    local input_y = b.y + b.h - 1
    local prompt = "> "
    buffer:set(b.x,     input_y, prompt:sub(1, 1), theme.palette.accent, bg_default)
    buffer:set(b.x + 1, input_y, prompt:sub(2, 2), theme.palette.accent, bg_default)
    local input_text = self_.state.input
    for i = 1, math.min(#input_text, b.w - 2) do
      buffer:set(b.x + 1 + i, input_y, input_text:sub(i, i), fg_default, bg_default)
    end
    if self_.state.focused then
      local cx = b.x + 2 + math.min(self_.state.input_col, b.w - 3)
      local under = input_text:sub(self_.state.input_col + 1, self_.state.input_col + 1)
      buffer:set(cx, input_y, under ~= "" and under or " ", bg_default, theme.palette.accent)
    end
    self_.dirty = false
  end

  self.on_event = function(self_, ev)
    if ev.type == "touch" and self_:hit(ev.x, ev.y) then
      self_.state.focused = true; self_:invalidate(); return true
    end
    if ev.type == "key" and ev.down and self_.state.focused then
      local s = self_.state
      if ev.code == 28 or ev.code == 156 then
        local line = s.input
        s.input, s.input_col = "", 0
        append(line .. "\n", nil)
        pcall(stdin_writer.write, stdin_writer, line .. "\n")
        self_:invalidate(); return true
      elseif ev.code == 14 then
        if s.input_col > 0 then
          s.input = s.input:sub(1, s.input_col - 1) .. s.input:sub(s.input_col + 1)
          s.input_col = s.input_col - 1
          self_:invalidate()
        end
        return true
      elseif ev.code == 211 then
        if s.input_col < #s.input then
          s.input = s.input:sub(1, s.input_col) .. s.input:sub(s.input_col + 2)
          self_:invalidate()
        end
        return true
      elseif ev.code == 203 then s.input_col = math.max(0, s.input_col - 1); self_:invalidate(); return true
      elseif ev.code == 205 then s.input_col = math.min(#s.input, s.input_col + 1); self_:invalidate(); return true
      elseif ev.code == 199 then s.input_col = 0; self_:invalidate(); return true
      elseif ev.code == 207 then s.input_col = #s.input; self_:invalidate(); return true
      elseif ev.char and ev.char >= 32 then
        local glyph = ev.char < 128 and string.char(ev.char) or ucs_char(ev.char)
        s.input = s.input:sub(1, s.input_col) .. glyph .. s.input:sub(s.input_col + 1)
        s.input_col = s.input_col + 1
        self_:invalidate(); return true
      end
    end
    if ev.type == "scroll" and self_:hit(ev.x, ev.y) then
      local total = #self_.state.lines
      local visible = self_.bounds.h - 1
      local max_scroll = math.max(0, total - visible)
      self_.state.scroll = math.max(0, math.min(max_scroll, self_.state.scroll + ev.dir))
      self_:invalidate(); return true
    end
    return false
  end

  self.close_input = function() pcall(stdin_writer.close, stdin_writer) end
  return self
end
]])
W('/sys/lib/ui/widgets/textarea.lua', [[
-- /sys/lib/ui/widgets/textarea.lua — multi-line text editing widget.
--
-- Holds a list of lines; cursor moves character-wise within a line and
-- line-wise across lines. Supports basic editing, scroll, and Lua-syntax
-- highlight (keywords + comments + strings + numbers) when `highlight`
-- prop is set to "lua".

local widget = require("lib.ui.widget")

local function ucs_len(s) local u = _G.unicode; return u and u.len and u.len(s) or #s end
local function ucs_sub(s, a, b) local u = _G.unicode; return u and u.sub and u.sub(s, a, b) or s:sub(a, b) end
local function ucs_char(c) local u = _G.unicode; return u and u.char and u.char(c) or string.char(c) end

local LUA_KEYWORDS = {}
for _, w in ipairs({
  "and","break","do","else","elseif","end","false","for","function","goto","if","in",
  "local","nil","not","or","repeat","return","then","true","until","while",
}) do LUA_KEYWORDS[w] = true end

local function highlight_line(line, theme)
  -- Returns an array of {start, len, fg} segments. The renderer paints text
  -- with the default fg first, then over-writes runs with the segment fg.
  local segs = {}
  local i, n = 1, #line
  local fg_str  = theme.input and (theme.input.fg or 0xE6E6E6) or 0xE6E6E6
  local fg_kw   = theme.palette.accent or 0x4F8AF0
  local fg_str2 = theme.palette.warn   or 0xE0A040
  local fg_num  = theme.palette.ok     or 0x6CCB6C
  local fg_com  = theme.palette.muted  or 0x808080

  while i <= n do
    local c = line:sub(i, i)
    if c == "-" and line:sub(i + 1, i + 1) == "-" then
      segs[#segs + 1] = { i, n - i + 1, fg_com }; break
    elseif c == '"' or c == "'" then
      local j = i + 1
      while j <= n do
        if line:sub(j, j) == "\\" then j = j + 2
        elseif line:sub(j, j) == c then j = j + 1; break
        else j = j + 1 end
      end
      segs[#segs + 1] = { i, j - i, fg_str2 }
      i = j
    elseif c:match("[%w_]") then
      local j = i
      while j <= n and line:sub(j, j):match("[%w_]") do j = j + 1 end
      local word = line:sub(i, j - 1)
      if LUA_KEYWORDS[word] then segs[#segs + 1] = { i, #word, fg_kw }
      elseif word:match("^%d") then segs[#segs + 1] = { i, #word, fg_num } end
      i = j
    else
      i = i + 1
    end
  end
  return segs
end

return function(props)
  local lines = {}
  for line in (props.text or ""):gmatch("([^\n]*)\n?") do lines[#lines + 1] = line end
  if #lines == 0 then lines = { "" } end

  return widget.new("textarea", {
    state = { lines = lines, row = 1, col = 0, scroll = 0 },

    measure = function(_, max_w, max_h) return max_w, max_h end,

    draw = function(self, buffer, theme)
      local b = self.bounds
      local fg = (theme.input and theme.input.fg) or theme.palette.fg
      local bg = (theme.input and theme.input.bg) or theme.palette.bg
      local lineno_fg = theme.palette.muted
      buffer:fill(b.x, b.y, b.w, b.h, " ", fg, bg)
      local left = 5                                   -- line-number gutter
      for row = 0, b.h - 1 do
        local line_idx = row + 1 + self.state.scroll
        local line = self.state.lines[line_idx]
        if line then
          local n = string.format("%4d", line_idx)
          for i = 1, 4 do buffer:set(b.x + i - 1, b.y + row, n:sub(i, i), lineno_fg, bg) end
          buffer:set(b.x + 4, b.y + row, " ", lineno_fg, bg)
          local visible = line:sub(1, b.w - left)
          for i = 1, #visible do
            buffer:set(b.x + left + i - 1, b.y + row, visible:sub(i, i), fg, bg)
          end
          if self.props.highlight == "lua" then
            for _, seg in ipairs(highlight_line(visible, theme)) do
              for j = 0, seg[2] - 1 do
                local x = b.x + left + seg[1] - 1 + j
                if x < b.x + b.w then
                  buffer:set(x, b.y + row, visible:sub(seg[1] + j, seg[1] + j), seg[3], bg)
                end
              end
            end
          end
        end
      end
      if self.state.focused then
        local cur_row = self.state.row - self.state.scroll
        if cur_row >= 1 and cur_row <= b.h then
          local cur_x = b.x + left + math.min(self.state.col, b.w - left - 1)
          local cy = b.y + cur_row - 1
          local under = self.state.lines[self.state.row]:sub(self.state.col + 1, self.state.col + 1)
          buffer:set(cur_x, cy, under ~= "" and under or " ", bg, theme.palette.accent)
        end
      end
      self.dirty = false
    end,

    on_event = function(self, ev)
      if ev.type == "touch" and self:hit(ev.x, ev.y) then
        self.state.focused = true
        local row = ev.y - self.bounds.y + 1 + self.state.scroll
        if self.state.lines[row] then self.state.row = row end
        self.state.col = math.max(0, math.min(#self.state.lines[self.state.row], ev.x - self.bounds.x - 5))
        self:invalidate(); return true
      end
      if ev.type == "key" and ev.down and self.state.focused then
        local s = self.state
        local cur_line = s.lines[s.row]
        local function update_scroll()
          if s.row - 1 < s.scroll then s.scroll = s.row - 1
          elseif s.row > s.scroll + self.bounds.h then s.scroll = s.row - self.bounds.h end
        end
        if ev.code == 200 and s.row > 1 then
          s.row = s.row - 1
          s.col = math.min(s.col, #s.lines[s.row]); update_scroll()
        elseif ev.code == 208 and s.row < #s.lines then
          s.row = s.row + 1
          s.col = math.min(s.col, #s.lines[s.row]); update_scroll()
        elseif ev.code == 203 and s.col > 0 then
          s.col = s.col - 1
        elseif ev.code == 205 and s.col < #cur_line then
          s.col = s.col + 1
        elseif ev.code == 199 then
          s.col = 0
        elseif ev.code == 207 then
          s.col = #cur_line
        elseif ev.code == 14 then  -- backspace
          if s.col > 0 then
            s.lines[s.row] = cur_line:sub(1, s.col - 1) .. cur_line:sub(s.col + 1)
            s.col = s.col - 1
          elseif s.row > 1 then
            local prev = s.lines[s.row - 1]
            s.col = #prev
            s.lines[s.row - 1] = prev .. cur_line
            table.remove(s.lines, s.row)
            s.row = s.row - 1; update_scroll()
          end
        elseif ev.code == 211 then  -- delete
          if s.col < #cur_line then
            s.lines[s.row] = cur_line:sub(1, s.col) .. cur_line:sub(s.col + 2)
          elseif s.row < #s.lines then
            s.lines[s.row] = cur_line .. s.lines[s.row + 1]
            table.remove(s.lines, s.row + 1)
          end
        elseif ev.code == 28 or ev.code == 156 then  -- enter
          local left, right = cur_line:sub(1, s.col), cur_line:sub(s.col + 1)
          s.lines[s.row] = left
          table.insert(s.lines, s.row + 1, right)
          s.row = s.row + 1; s.col = 0; update_scroll()
        elseif ev.char and ev.char >= 32 then
          local glyph = ev.char < 128 and string.char(ev.char) or ucs_char(ev.char)
          s.lines[s.row] = cur_line:sub(1, s.col) .. glyph .. cur_line:sub(s.col + 1)
          s.col = s.col + 1
        else
          return false
        end
        self:invalidate(); return true
      end
      return false
    end,

    text = function(self) return table.concat(self.state.lines, "\n") end,
    set_text = function(self, t)
      self.state.lines = {}
      for line in (t or ""):gmatch("([^\n]*)\n?") do self.state.lines[#self.state.lines + 1] = line end
      if #self.state.lines == 0 then self.state.lines = { "" } end
      self.state.row, self.state.col, self.state.scroll = 1, 0, 0
      self:invalidate()
    end,
  }, props or {})
end
]])
W('/sys/lib/ui/widgets/wallpaper.lua', [[
-- /sys/lib/ui/widgets/wallpaper.lua — desktop background.
--
-- Two modes: solid colour (default) and pattern (a function the caller
-- supplies that returns ch, fg, bg per cell). Patterns enable the rain /
-- dvd / starfield wallpapers without the compositor knowing about them.

local widget = require("lib.ui.widget")

return function(props)
  return widget.new("wallpaper", {
    measure = function(self, max_w, max_h) return max_w, max_h end,
    draw = function(self, buffer, theme)
      local b = self.bounds
      local desktop_bg = (theme.desktop and theme.desktop.bg) or theme.palette.bg
      local color = self.props.color or desktop_bg
      if self.props.pattern then
        for y = b.y, b.y + b.h - 1 do
          for x = b.x, b.x + b.w - 1 do
            local ch, fg, bg = self.props.pattern(x, y, theme)
            buffer:set(x, y, ch or " ", fg or theme.palette.fg, bg or color)
          end
        end
      else
        buffer:fill(b.x, b.y, b.w, b.h, " ", theme.palette.fg, color)
      end
      self.dirty = false
    end,
  }, props or {})
end
]])
W('/sys/lib/ui/widgets/window.lua', [[
-- /sys/lib/ui/widgets/window.lua — bordered, titled, draggable container.
local widget = require("lib.ui.widget")

local function ucs_len(s) local u = _G.unicode; return u and u.len and u.len(s) or #s end

return function(props)
  local w = widget.new("window", {
    state = { dragging = false, drag_dx = 0, drag_dy = 0 },

    measure = function(self, max_w, max_h)
      local cw, ch = max_w, max_h
      if self.children[1] then cw, ch = self.children[1]:measure(max_w - 2, max_h - 2) end
      return math.min(self.props.w or (cw + 2), max_w),
             math.min(self.props.h or (ch + 2), max_h)
    end,

    _layout_children = function(self)
      local b = self.bounds
      if self.children[1] then
        self.children[1]:layout(b.x + 1, b.y + 2, b.w - 2, b.h - 3)
      end
    end,

    draw = function(self, buffer, theme)
      local b = self.bounds
      local t = theme.window or {}
      local bg = t.bg or theme.palette.surface
      local fg = t.fg or theme.palette.fg
      buffer:fill(b.x, b.y, b.w, b.h, " ", fg, bg)
      buffer:fill(b.x, b.y, b.w, 1, " ", t.title_fg or 0xFFFFFF, t.title_bg or theme.palette.accent)
      local title = self.props.title or ""
      local n = math.min(ucs_len(title), b.w - 4)
      for i = 1, n do buffer:set(b.x + 1 + i, b.y, title:sub(i, i), t.title_fg or 0xFFFFFF, t.title_bg or theme.palette.accent) end
      if self.props.closable ~= false then
        buffer:set(b.x + b.w - 2, b.y, "x", t.title_fg or 0xFFFFFF, t.title_bg or theme.palette.accent)
      end
      for _, c in ipairs(self.children) do if c.visible then c:draw(buffer, theme) end end
      self.dirty = false
    end,

    on_event = function(self, ev)
      if ev.type == "touch" and self:hit(ev.x, ev.y) then
        if ev.y == self.bounds.y then
          if self.props.closable ~= false and ev.x == self.bounds.x + self.bounds.w - 2 then
            if self.props.on_close then self.props.on_close(self) end
            return true
          end
          self.state.dragging = true
          self.state.drag_dx = ev.x - self.bounds.x
          self.state.drag_dy = ev.y - self.bounds.y
          return true
        end
      elseif ev.type == "drag" and self.state.dragging then
        local nx, ny = ev.x - self.state.drag_dx, ev.y - self.state.drag_dy
        self.bounds.x, self.bounds.y = nx, ny
        if self.children[1] then
          self.children[1]:layout(nx + 1, ny + 2, self.bounds.w - 2, self.bounds.h - 3)
        end
        self:invalidate(); return true
      elseif ev.type == "drop" then
        self.state.dragging = false; return false
      end
      -- Forward unhandled events to children.
      for i = #self.children, 1, -1 do
        if self.children[i].visible and self.children[i]:on_event(ev) then return true end
      end
      return false
    end,
  }, props or {})
  if props and props.body then w:add_child(props.body) end
  return w
end
]])
W('/sys/std/fstream.lua', [[
-- /sys/std/fstream.lua — Stream wrapper around a vfs file handle.

local M = {}

local stream = require("std.stream")
local vfs    = require("k.vfs")

function M.open(path, mode)
  local h, err = vfs.open(path, mode or "r")
  if not h then return nil, err end
  return stream.new {
    _read  = function(_, n) return h:read(n) end,
    _write = function(self, s) return h:write(s) and self or nil end,
    _close = function() return h:close() end,
    _seek  = function(_, whence, off) return h:seek(whence, off) end,
  }
end

return M
]])
W('/sys/std/io.lua', [[
-- /sys/std/io.lua — process-aware io binding.
--
-- Every process gets its own `io` table whose stdin/stdout/stderr are bound
-- to that process's streams. `proc.exec` builds one of these and injects it
-- into the loaded chunk's environment so commands see a familiar Lua-like
-- io library while staying fully sandboxed.

local M = {}

local fstream = require("std.fstream")

function M.bind(streams)
  -- streams = { stdin = Stream, stdout = Stream, stderr = Stream }
  local t = {
    stdin  = streams.stdin,
    stdout = streams.stdout,
    stderr = streams.stderr,
  }
  function t.write(...)
    return t.stdout:write(...)
  end
  function t.read(...)
    return t.stdin:read(...)
  end
  function t.lines(path)
    if path then
      local s, err = fstream.open(path, "r")
      if not s then return error(err, 2) end
      return function()
        local l = s:read("l")
        if l == nil then s:close() end
        return l
      end
    end
    return t.stdin:lines("l")
  end
  function t.open(path, mode) return fstream.open(path, mode or "r") end
  function t.input()  return t.stdin  end
  function t.output() return t.stdout end
  return t
end

function M.print_for(io_tbl)
  return function(...)
    local n = select("#", ...)
    local parts = {}
    for i = 1, n do parts[i] = tostring((select(i, ...))) end
    io_tbl.stdout:write(table.concat(parts, "\t"), "\n")
  end
end

return M
]])
W('/sys/std/pipe.lua', [[
-- /sys/std/pipe.lua — in-memory pipe between two cooperative processes.
--
-- The reader-side blocks on sched.wait until data arrives or the pipe closes.
-- The writer-side enqueues bytes and publishes a signal so the reader can
-- wake up. We use the IPC bus rather than direct coroutine.resume so the
-- scheduler stays the only place that drives processes.

local M = {}

local sched = require("k.sched")
local ipc   = require("k.ipc")
local stream = require("std.stream")

local _seq = 0
local function new_pipe()
  _seq = _seq + 1
  local id = _seq
  local channel = "pipe.wake." .. id
  local state = {
    id      = id,
    chunks  = {},                                -- queue of pending strings
    closed  = false,
    channel = channel,
  }

  local function enqueue(data)
    state.chunks[#state.chunks + 1] = data
    ipc.publish(channel, true)
  end

  local function dequeue(max)
    local head = state.chunks[1]
    if not head then return nil end
    if #head <= max then
      table.remove(state.chunks, 1)
      return head
    end
    state.chunks[1] = head:sub(max + 1)
    return head:sub(1, max)
  end

  local read_end = stream.new {
    _read = function(self, n)
      n = n or math.huge
      while #state.chunks == 0 and not state.closed do
        sched.wait(function(name) return name == "__pipe__" .. id end, math.huge)
      end
      return dequeue(n) or (state.closed and "" or nil)
    end,
    _close = function() state.closed = true; ipc.publish(channel, true); return true end,
  }
  local write_end = stream.new {
    _write = function(self, s)
      if state.closed then return nil, "broken pipe" end
      if s ~= "" then enqueue(s) end
      return self
    end,
    _close = function() state.closed = true; ipc.publish(channel, true); return true end,
  }

  -- The reader's sched.wait filter is by raw signal name. We hook the IPC
  -- channel and bridge it into a synthetic "__pipe__<id>" signal that the
  -- scheduler's filter machinery understands.
  ipc.subscribe(channel, function()
    computer.pushSignal("__pipe__" .. id)
  end)

  return read_end, write_end
end

M.new = new_pipe
return M
]])
W('/sys/std/stream.lua', [[
-- /sys/std/stream.lua — base stream type used by every I/O endpoint.
--
-- A stream owns no backing storage of its own; concrete types provide
-- `_read`/`_write`/`_close` and the base wraps them with a small line buffer
-- so `read("l")` and `lines()` work uniformly across pipes, tty and files.
--
-- The interface is the same kind of layered design Lua's `io` library uses:
-- raw byte reads/writes underneath, line-aware helpers on top.

local M = {}

local Stream = {}
Stream.__index = Stream

function Stream:read(fmt)
  fmt = fmt or "l"
  if type(fmt) == "number" then return self:_read(fmt) end
  if fmt == "*a" or fmt == "a" then
    local parts = {}
    while true do
      local chunk = self:_read(4096)
      if not chunk or chunk == "" then break end
      parts[#parts + 1] = chunk
    end
    return table.concat(parts)
  elseif fmt == "*l" or fmt == "l" or fmt == "*L" or fmt == "L" then
    local keep_eol = fmt:sub(-1) == "L"
    local buf = self._linebuf or ""
    while true do
      local nl = buf:find("\n", 1, true)
      if nl then
        local line = buf:sub(1, nl - (keep_eol and 0 or 1))
        self._linebuf = buf:sub(nl + 1)
        return line
      end
      local chunk = self:_read(256)
      if not chunk or chunk == "" then
        if buf == "" then self._linebuf = ""; return nil end
        self._linebuf = ""
        return buf
      end
      buf = buf .. chunk
    end
  elseif fmt == "*n" or fmt == "n" then
    error("stream:read('n') not supported", 2)
  end
  error("invalid stream:read format: " .. tostring(fmt), 2)
end

function Stream:write(...)
  for i = 1, select("#", ...) do
    local ok, err = self:_write(tostring((select(i, ...))))
    if not ok then return nil, err end
  end
  return self
end

function Stream:lines(...)
  local args = table.pack(...)
  return function() return self:read(args[1] or "l") end
end

function Stream:close()
  if self._closed then return true end
  self._closed = true
  if self._close then return self:_close() end
  return true
end

function Stream:flush()
  if self._flush then return self:_flush() end
  return self
end

function Stream:is_closed() return self._closed == true end
function Stream:seek() return nil, "stream is not seekable" end

function M.new(impl)
  -- impl provides _read / _write / _close / _flush; missing methods become
  -- no-ops or "not supported" errors via the corresponding Stream methods.
  local s = setmetatable({}, Stream)
  for k, v in pairs(impl) do s[k] = v end
  return s
end

function M.null()
  -- A stream that immediately returns EOF on read and accepts writes silently.
  -- Useful when wiring "/dev/null" semantics into a process's stdin or stderr.
  return M.new {
    _read  = function() return nil end,
    _write = function(self) return self end,
  }
end

M.Stream = Stream
return M
]])
W('/sys/svc/init.lua', [=[
-- /sys/svc/init.lua — first user process. Brings up the service manager
-- and lets it own the rest of userland. When /etc/boot.selftest is present,
-- runs the in-kernel test battery instead and shuts the machine down.

local M = {}

local sched   = require("k.sched")
local log     = require("k.log")
local vfs     = require("k.vfs")
local exec    = require("k.exec")
local ipc     = require("k.ipc")
local console = require("lib.term.console")
local svcmgr  = require("lib.svc.manager")

local function find_writable_mount()
  for _, m in ipairs(vfs.mounts()) do
    if m.prefix:sub(1, 5) == "/mnt/" then return m.prefix end
  end
end

-- ---- selftest -----------------------------------------------------------

local function selftest_active() return vfs.exists("/etc/boot.selftest") end

local function selftest_run()
  local results = { _OSVERSION, "uptime=" .. tostring(computer.uptime()) }
  local function check(name, fn)
    local ok, err = pcall(fn)
    results[#results + 1] = (ok and "PASS " or "FAIL ") .. name ..
      (ok and "" or "  -- " .. tostring(err))
  end

  check("vfs.list /sys",  function() assert(#vfs.list("/sys") > 0) end)
  check("vfs.list /bin",  function() assert(#vfs.list("/bin") > 0) end)
  check("vfs read /init", function() local s = vfs.read_all("/init.lua"); assert(s and #s > 0) end)
  check("sched.sleep(0)", function() sched.sleep(0) end)
  check("ipc echo",       function()
    local got
    local h = ipc.subscribe("test.echo", function(p) got = p end)
    ipc.publish("test.echo", { v = 42 })
    ipc.unsubscribe(h)
    assert(got and got.v == 42, "echo failed")
  end)
  check("term.init",   function() console.init() end)
  check("gpu writeln", function() console.writeln(_OSVERSION) end)

  local function shell_capture(script)
    local pipe   = require("std.pipe")
    local stream = require("std.stream")
    local r, w = pipe.new()
    local p = exec.exec("/bin/sh.lua", { "-c", script }, {
      streams   = { stdin = stream.null(), stdout = w, stderr = w },
      shell_env = { PATH = "/bin", PWD = "/" },
      caps = { "*" }, name = "sh-test",
    })
    assert(p, "exec.exec failed")
    sched.wait_pid(p.id)
    pcall(w.close, w)
    return r:read("a") or ""
  end

  check("shell pipe",        function() assert(shell_capture("echo OCOSLINE | grep CO"):find("OCOSLINE", 1, true)) end)
  check("shell &&",          function() assert(shell_capture("true && echo OK_AND"):find("OK_AND", 1, true)) end)
  check("shell ||",          function() assert(shell_capture("false || echo OK_OR"):find("OK_OR", 1, true)) end)
  check("shell var",         function() assert(shell_capture("set X=ocosvar; echo $X"):find("ocosvar", 1, true)) end)
  check("shell redirect >",  function()
    local mp = find_writable_mount(); assert(mp, "no writable mount")
    local target = mp .. "/redir.tmp"
    shell_capture("echo OCOSREDIR > " .. target)
    local s = vfs.read_all(target) or ""
    assert(s:find("OCOSREDIR", 1, true), "redir file: " .. tostring(s))
    pcall(vfs.remove, target)
  end)

  check("svc framework", function()
    svcmgr.load_units("/etc/services")
    local list = svcmgr.list()
    local ids = {}
    for _, s in ipairs(list) do ids[s.id] = true end
    assert(ids.logd and ids.sessiond, "missing services in unit dir")
  end)

  check("sha256 vectors", function()
    local sha = require("lib.codec.sha256")
    assert(sha.hex("") == "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855",
      "empty: " .. sha.hex(""))
    assert(sha.hex("abc") == "ba7816bf8f01cfea414140de5dae2223b00361a396177a9cb410ff61f20015ad",
      "abc: " .. sha.hex("abc"))
    -- Long-message vector trimmed to 64 KiB so tier-1 RAM machines can run
    -- the test; the SHA-256 spec test vectors are also FIPS-published only
    -- for short inputs.
    local long = string.rep("OCOS", 16384)         -- 64 KiB
    local h = sha.hex(long)
    assert(#h == 64, "long output length: " .. #h)
  end)

  check("semver constraints", function()
    local s = require("lib.codec.semver")
    assert(s.satisfies("1.2.3", ">=1.0.0"))
    assert(not s.satisfies("1.2.3", "<1.0.0"))
    assert(s.satisfies("1.2.3", ">=1.0,<2.0"))
    assert(s.satisfies("1.2.3", "^1.0"))
    assert(not s.satisfies("2.0.0", "^1.0"))
    assert(s.satisfies("1.2.3", "~1.2"))
    assert(not s.satisfies("1.3.0", "~1.2"))
  end)

  check("ui buffer + flush", function()
    -- Verifies the diff-based flush coalesces same-colour runs and skips
    -- unchanged cells.
    local Buffer = require("lib.ui.buffer")
    local fake_ops = {}
    local fake_gpu = {
      set    = function(x, y, s) fake_ops[#fake_ops + 1] = { "set", x, y, s } end,
      fill   = function(...) fake_ops[#fake_ops + 1] = { "fill", ... } end,
      copy   = function(...) fake_ops[#fake_ops + 1] = { "copy", ... } end,
      set_fg = function(c) fake_ops[#fake_ops + 1] = { "fg", c } end,
      set_bg = function(c) fake_ops[#fake_ops + 1] = { "bg", c } end,
    }
    local buf = Buffer.new(10, 3)
    buf:set(1, 1, "A", 0xFF0000, 0x000000)
    buf:set(2, 1, "B", 0xFF0000, 0x000000)
    buf:set(3, 1, "C", 0xFF0000, 0x000000)
    buf:flush(fake_gpu)
    local sets = 0
    for _, op in ipairs(fake_ops) do if op[1] == "set" then sets = sets + 1 end end
    assert(sets >= 1, "no gpu.set emitted")
    -- Second flush with no changes should be a no-op.
    fake_ops = {}; buf:flush(fake_gpu)
    for _, op in ipairs(fake_ops) do
      assert(op[1] ~= "set", "redundant set emitted on identical frame")
    end
  end)

  check("ui theme + widgets", function()
    local theme_m = require("lib.ui.theme")
    local widgets = {
      label    = require("lib.ui.widgets.label"),
      button   = require("lib.ui.widgets.button"),
      checkbox = require("lib.ui.widgets.checkbox"),
    }
    local Buffer = require("lib.ui.buffer")
    local theme = assert(theme_m.load("default"))
    assert(theme.palette and theme.palette.bg, "default theme missing palette.bg")
    local light = assert(theme_m.load("light"))
    assert(light.palette.bg ~= theme.palette.bg, "light should override bg")

    local buf = Buffer.new(20, 3)
    local lab = widgets.label({ text = "Hello" })
    lab:layout(1, 1, 20, 1); lab:draw(buf, theme)
    assert(buf:get(1, 1) == "H", "label first cell")
    assert(buf:get(5, 1) == "o", "label fifth cell")

    local btn = widgets.button({ text = "Go", on_click = function() end })
    btn:layout(1, 2, 6, 1); btn:draw(buf, theme)
    assert(buf:get(3, 2) == "G" or buf:get(4, 2) == "G", "button rendered")

    local chk = widgets.checkbox({ text = "On", checked = true })
    chk:layout(1, 3, 8, 1); chk:draw(buf, theme)
    assert(buf:get(2, 3) == "x", "checkbox marked")
  end)

  check("ui layout flex", function()
    local widgets = require("lib.ui.widget")
    local layout  = require("lib.ui.layout")
    local label   = require("lib.ui.widgets.label")
    local row = layout.row({
      gap = 1,
      children = { label({ text = "ab" }), label({ text = "cd" }), label({ text = "ef" }) },
    })
    row:layout(1, 1, 20, 1)
    assert(row.children[1].bounds.x == 1)
    assert(row.children[2].bounds.x == 4, "second child x: " .. row.children[2].bounds.x)
    assert(row.children[3].bounds.x == 7, "third child x: "  .. row.children[3].bounds.x)
  end)

  check("pbkdf2 + users", function()
    local pbkdf2 = require("lib.codec.pbkdf2")
    local hex = pbkdf2.derive("password", "salt", 100)
    assert(#hex == 64, "derive length: " .. #hex)
    assert(pbkdf2.verify("password", "salt", 100, hex))
    assert(not pbkdf2.verify("wrong", "salt", 100, hex))

    local users = require("lib.auth.users")
    local ok = users.create("ocos_test_user", "secret123", { iters = 200 })
    assert(ok, "create user")
    assert(users.verify("ocos_test_user", "secret123"))
    assert(not users.verify("ocos_test_user", "wrong"))
    assert(users.set_password("ocos_test_user", "newpass", { iters = 200 }))
    assert(users.verify("ocos_test_user", "newpass"))
    assert(not users.verify("ocos_test_user", "secret123"))
    assert(users.remove("ocos_test_user"))
    assert(not users.get("ocos_test_user"))
  end)

  check("capability enforcement", function()
    local cap = require("k.cap")
    cap.set_enforce(true)
    assert(cap.check({ ["*"] = true }, "syscall:write:/etc/passwd"))
    assert(not cap.check({ ["component:gpu"] = true }, "syscall:write:/etc/passwd"))
    assert(cap.check({ ["syscall:write:/var/*"] = true }, "syscall:write:/var/log/x"))
    assert(not cap.check({ ["syscall:write:/var/*"] = true }, "syscall:write:/etc/x"))
    cap.set_enforce(false)
  end)

  check("inspect cycles", function()
    local inspect = require("lib.devtools.inspect")
    local t = { name = "x", num = 42 }
    t.self = t
    local s = inspect.inspect(t)
    assert(s:find("name = \"x\"", 1, true), "name field: " .. s)
    assert(s:find("<table:", 1, true), "cycle marker: " .. s)
  end)

  check("profile bench", function()
    local prof = require("lib.devtools.profile")
    local r = prof.bench("noop", 1000, function() end)
    assert(r.iterations == 1000, "iterations recorded")
    assert(r.elapsed_s >= 0, "elapsed: " .. tostring(r.elapsed_s))
    local report = prof.format({ r })
    assert(report:find("noop", 1, true), "report contains name")
  end)

  check("json codec", function()
    local json = require("lib.codec.json")
    local round = function(v)
      local s = json.encode(v)
      local d, err = json.decode(s)
      assert(d, "decode: " .. tostring(err))
      return s, d
    end
    -- Primitives
    assert(json.decode("42") == 42)
    assert(json.decode("true") == true)
    assert(json.decode("null") == json.null)
    assert(json.decode([["hi"]]) == "hi")
    -- Round-trip an object.
    local s = round({ a = 1, b = "x", c = { 1, 2, 3 }, d = true })
    assert(s:find("%[1,2,3%]"), "array encoded: " .. s)
    -- Nested escape.
    local s2 = json.encode({ k = "with \"quotes\" and\n newline" })
    assert(s2:find("\\n", 1, true), "newline escaped: " .. s2)
    assert(json.decode(s2).k:find("quotes", 1, true))
    -- Reject malformed.
    assert(not json.decode("{,}"))
    assert(not json.decode("[1,]"))
  end)

  check("locale framework", function()
    local lang = require("lib.lang")
    assert(lang.t("dock.files") ~= "<dock.files>", "english fallback works")
    assert(lang.set("uk"), "set uk")
    assert(lang.t("dock.files"):find("Файли", 1, true), "ukrainian: " .. lang.t("dock.files"))
    assert(lang.set("en"), "set en")
    assert(lang.t("dock.files") == "Files")
    assert(lang.t("missing.key.xyz") == "<missing.key.xyz>", "missing keys are visible")
    local available = lang.list_available()
    assert(#available >= 3, "available locales: " .. tostring(#available))
  end)

  check("stress: 50 procs", function()
    local proc = require("k.proc")
    local before = #proc.list()
    local done = {}
    for i = 1, 50 do
      local id_local = i
      sched.spawn(function() sched.sleep(0); done[id_local] = true end,
        { name = "stress-" .. i, caps = { "*" } })
    end
    for _ = 1, 20 do sched.sleep(0) end
    local count = 0; for _ in pairs(done) do count = count + 1 end
    assert(count == 50, "completed " .. count .. "/50")
    assert(#proc.list() <= before + 2, "proc table leaked: " .. (#proc.list() - before))
  end)

  check("stress: 1000 ipc msgs", function()
    local count = 0
    local h = ipc.subscribe("stress.msg", function() count = count + 1 end)
    for i = 1, 1000 do ipc.publish("stress.msg", i) end
    ipc.unsubscribe(h)
    assert(count == 1000, "delivered " .. count .. "/1000")
  end)

  check("apps load cleanly", function()
    local Buffer = require("lib.ui.buffer")
    local stub_buf = Buffer.new(80, 24)
    local stub_compositor = {
      theme       = require("lib.ui.theme").current(),
      add         = function(_, w) w:layout(1, 1, 80, 24); return w end,
      invalidate  = function() end,
      size        = function() return 80, 24 end,
      set_theme   = function() end,
    }
    for _, app in ipairs({ "desktop", "files", "dmesg", "inspect", "settings" }) do
      local path = "/apps/" .. app .. ".app/Main.lua"
      local src = vfs.read_all(path); assert(src, "cannot read " .. path)
      local fn, lerr = load(src, "=" .. path, "t", _G)
      assert(fn, app .. " load: " .. tostring(lerr))
      local ok, rerr = pcall(fn, {}, {}, { compositor = stub_compositor })
      assert(ok, app .. " run: " .. tostring(rerr))
    end
  end)

  check("pkg install + verify + uninstall", function()
    local mp = find_writable_mount(); assert(mp, "no writable mount")
    local sha = require("lib.codec.sha256")
    local install = require("lib.pkg.install")
    local db = require("lib.pkg.db")

    local src_dir = mp .. "/pkg-test-src"
    local dst_root = mp .. "/pkg-test-dst/"
    pcall(vfs.mkdir, src_dir)
    pcall(vfs.mkdir, src_dir .. "/lib")
    pcall(vfs.mkdir, mp .. "/pkg-test-dst")
    local payload = "return function() return 'hello-from-pkg' end\n"
    vfs.write_all(src_dir .. "/lib/hello.lua", payload)
    local digest = sha.hex(payload)
    local manifest_src = string.format([[
return {
  id = "ocos.test.hello",
  name = "Hello",
  version = "0.1.0",
  description = "self-test package",
  prefix = %q,
  files = { ["lib/hello.lua"] = { sha256 = %q } },
}
]], dst_root, digest)
    vfs.write_all(src_dir .. "/manifest.cfg", manifest_src)

    local mfst, err = install.install_dir(src_dir)
    assert(mfst, "install: " .. tostring(err))
    assert(vfs.exists(dst_root .. "lib/hello.lua"), "destination file missing")
    local vok, verr = install.verify("ocos.test.hello")
    assert(vok, "verify after install: " .. tostring(verr))

    -- Tampered file must be detected.
    vfs.write_all(dst_root .. "lib/hello.lua", payload .. "garbage")
    local ok = install.verify("ocos.test.hello")
    assert(not ok, "verify must fail on tampered file")
    -- Restore + uninstall.
    vfs.write_all(dst_root .. "lib/hello.lua", payload)
    assert(install.verify("ocos.test.hello"), "post-restore verify failed")
    assert(install.uninstall("ocos.test.hello"))
    assert(not vfs.exists(dst_root .. "lib/hello.lua"), "uninstall left files")
    pcall(vfs.remove, src_dir .. "/manifest.cfg")
    pcall(vfs.remove, src_dir .. "/lib/hello.lua")
    pcall(vfs.remove, src_dir .. "/lib")
    pcall(vfs.remove, src_dir)
    pcall(vfs.remove, mp .. "/pkg-test-dst/lib")
    pcall(vfs.remove, mp .. "/pkg-test-dst")
  end)

  for _, e in ipairs(log.entries()) do
    results[#results + 1] = string.format("[%8.3f] %s %s: %s", e.time, e.level, e.tag, e.msg)
  end
  local mp = find_writable_mount()
  if mp then vfs.write_all(mp .. "/selftest.log", table.concat(results, "\n") .. "\n") end
  log.info("selftest", "wrote selftest.log; shutting down")
  sched.sleep(0.1)
  computer.shutdown(false)
end

-- ---- normal supervised startup -----------------------------------------

function M.main()
  log.info("init", "init service starting")
  if selftest_active() then return selftest_run() end

  -- Bring up the supervisor first so any subsequent proc.exit is observed.
  svcmgr.bind_supervisor()
  local order, err = svcmgr.start_all_autostart("/etc/services")
  if not order then
    log.error("init", "service ordering failed: " .. tostring(err))
  else
    log.info("init", "started services: " .. table.concat(order, ", "))
  end

  -- Init never exits. Sleep in long stretches so the watchdog stays happy.
  while true do sched.sleep(60) end
end

return M
]=])
W('/sys/svc/logd.lua', [[
-- /sys/svc/logd.lua — kernel-log persister.
--
-- Subscribes to the in-RAM ring buffer's live tap and appends each entry
-- to /var/log/dmesg.log on the first writable mount, rotating when the
-- file grows past 64 KiB. Exits when its `svc.stop.logd` channel fires.

local sched = require("k.sched")
local log   = require("k.log")
local vfs   = require("k.vfs")
local ipc   = require("k.ipc")

local MAX_BYTES = 64 * 1024
local KEEP      = 4

local function pick_log_path()
  for _, m in ipairs(vfs.mounts()) do
    if m.prefix:sub(1, 5) == "/mnt/" then
      pcall(vfs.mkdir, m.prefix .. "/var")
      pcall(vfs.mkdir, m.prefix .. "/var/log")
      return m.prefix .. "/var/log/dmesg.log"
    end
  end
end

local function rotate(path)
  for i = KEEP - 1, 1, -1 do
    local from, to = path .. "." .. i, path .. "." .. (i + 1)
    if vfs.exists(from) then pcall(vfs.rename, from, to) end
  end
  if vfs.exists(path) then pcall(vfs.rename, path, path .. ".1") end
end

local function append_line(path, line)
  local size = vfs.size(path) or 0
  if size + #line > MAX_BYTES then rotate(path) end
  local h, err = vfs.open(path, "a")
  if not h then return nil, err end
  h:write(line)
  h:close()
  return true
end

local function format_entry(e)
  return string.format("[%8.3f] %s %s: %s\n", e.time, e.level, e.tag, e.msg)
end

local path = pick_log_path()
if not path then
  log.warn("logd", "no writable mount; logd is exiting")
  return 0
end

-- Catch up: write everything currently buffered.
for _, e in ipairs(log.entries()) do append_line(path, format_entry(e)) end

-- Live tap. The subscribe callback runs in whichever coroutine published the
-- entry, so we keep its body trivial — just enqueue.
local pending = {}
local NOTIFY = "__logd_entry"
local STOP   = "__logd_stop"
local stopping = false

local log_handle  = log.subscribe(nil, function(entry)
  pending[#pending + 1] = entry
  computer.pushSignal(NOTIFY)
end)
local stop_handle = ipc.subscribe("svc.stop.logd", function()
  stopping = true; computer.pushSignal(STOP)
end)

while not stopping do
  sched.wait(function(name) return name == NOTIFY or name == STOP end, math.huge)
  while #pending > 0 do
    append_line(path, format_entry(table.remove(pending, 1)))
  end
end

log.unsubscribe(log_handle)
ipc.unsubscribe(stop_handle)
return 0
]])
W('/sys/svc/sessiond.lua', [[
-- /sys/svc/sessiond.lua — interactive session manager.
--
-- Owns the console for the duration of the session. When /etc/passwd has
-- entries, gates the shell with a login prompt and applies the verified
-- user's capabilities; otherwise drops straight into a privileged root
-- shell suitable for first-boot configuration.

local sched   = require("k.sched")
local log     = require("k.log")
local vfs     = require("k.vfs")
local exec    = require("k.exec")
local ipc     = require("k.ipc")
local console = require("lib.term.console")
local tty     = require("lib.term.tty")
local users   = require("lib.auth.users")
local audit   = require("lib.auth.audit")

local function print_motd(streams)
  if not vfs.exists("/etc/motd") then return end
  local h = vfs.open("/etc/motd", "r")
  if not h then return end
  while true do
    local chunk = h:read(4096); if not chunk or chunk == "" then break end
    streams.stdout:write(chunk)
  end
  h:close()
end

-- Read a password from the keyboard without echoing the characters.
local function read_password()
  local buf = {}
  while true do
    local ev = sched.wait(function(name) return name == "key_down" end)
    if ev then
      local _, char, code = ev.args[1], ev.args[2], ev.args[3]
      if code == 28 then console.writeln(""); return table.concat(buf) end
      if code == 14 then if #buf > 0 then buf[#buf] = nil end
      elseif char and char >= 32 and char < 127 then
        buf[#buf + 1] = string.char(char); console.write("*")
      end
    end
  end
end

local function login()
  for attempt = 1, 3 do
    console.write("login: ")
    local user = console.read_line()
    if not user or user == "" then return nil end
    console.write("password: ")
    local pw = read_password()
    if users.verify(user, pw) then
      audit.write({ kind = "login.ok", user = user })
      return users.get(user), user
    end
    audit.write({ kind = "login.fail", user = user })
    console.writeln("Login incorrect.")
  end
  return nil
end

local stopping = false
ipc.subscribe("svc.stop.sessiond", function()
  stopping = true; computer.pushSignal("__sessiond_stop")
end)

console.init()

while not stopping do
  console.set_fg(0xCCCCFF); console.writeln(_OSVERSION)
  console.set_fg(0xCCCCCC)
  local streams = { stdin = tty.stdin(), stdout = tty.stdout(), stderr = tty.stderr() }
  print_motd(streams)
  console.writeln("")

  local rec, name
  if users.empty() then
    rec, name = { home = "/home", caps = { "*" } }, "root"
  else
    rec, name = login()
    if not rec then sched.sleep(1); goto continue end
  end

  local sh, err = exec.exec("/bin/sh.lua", {}, {
    streams   = streams,
    shell_env = { PATH = "/bin", PWD = rec.home or "/home", HOME = rec.home or "/home", USER = name },
    caps      = rec.caps or {},
    name      = "sh:" .. name,
  })
  if not sh then
    streams.stderr:write("sessiond: cannot launch shell: " .. tostring(err) .. "\n")
    log.error("sessiond", "shell launch failed: " .. tostring(err))
    sched.sleep(2)
  else
    sched.wait_pid(sh.id)
    audit.write({ kind = "logout", user = name })
    if not stopping then
      console.writeln("[shell exited]")
      sched.sleep(0.2)
    end
  end
  ::continue::
end
return 0
]])
W('/sys/svc/uid.lua', [[
-- /sys/svc/uid.lua — UI/desktop service.
--
-- Owns the compositor for the lifetime of the GUI session. Launches the
-- desktop app first, then any other autostarted GUI apps. When the user
-- chooses to log out, the compositor is torn down and uid exits, allowing
-- the supervisor to fall back to sessiond if no other GUI service starts.

local sched   = require("k.sched")
local ipc     = require("k.ipc")
local log     = require("k.log")
local ui      = require("lib.ui")
local exec    = require("k.exec")
local theme_m = require("lib.ui.theme")
local stream  = require("std.stream")
local vfs     = require("k.vfs")

local STOP = "__svc_stop_uid"
ipc.subscribe("svc.stop.uid", function() computer.pushSignal(STOP) end)

local theme = theme_m.current()

local compositor, err = ui.compositor.new({ theme = theme })
if not compositor then
  log.error("uid", "compositor: " .. tostring(err))
  return 1
end

-- Make the live session available to the desktop app and any other GUI
-- consumers via a well-known global. We do not pass it on the command line
-- because spawned apps live in their own processes; the session table is
-- read inside their loaded chunks via _G.
_G._OCOS_UI_SESSION = { compositor = compositor }

-- Launch the desktop app inside the same coroutine; its Main.lua simply
-- adds widgets to the compositor and returns.
local desktop_main = "/apps/desktop.app/Main.lua"
if vfs.exists(desktop_main) then
  local fn, lerr = load(vfs.read_all(desktop_main), "=" .. desktop_main, "t", _G)
  if fn then pcall(fn, {}, {}, _G._OCOS_UI_SESSION)
  else log.error("uid", "desktop load: " .. tostring(lerr)) end
end

-- Subscribe to stop request via a flag we'll check between event ticks.
local stop_req = false
ipc.subscribe("svc.stop.uid", function() stop_req = true; compositor:request_stop() end)

compositor:run()

_G._OCOS_UI_SESSION = nil
return 0
]])


